// --- Supabase Config ---
//  SECURITY WARNING: The SUPABASE_KEY is an 'anon' key and is visible in the frontend. 
// To prevent data breaches, you MUST enable Row Level Security (RLS) on your Supabase dashboard.
// Each table (parties, inventory, invoices, etc.) should have an RLS policy that restricts 
// access to the 'anon' role with appropriate 'USING' and 'CHECK' expressions.
const SUPABASE_URL = 'https://pfukfcnxvrkefcmevcxq.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBmdWtmY254dnJrZWZjbWV2Y3hxIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM0NTk2MjksImV4cCI6MjA4OTAzNTYyOX0.tPCMJ431g5iHb9qkRSzMWlV0dL_iVPNXPnQjJ0DwZPw';
const supabaseClient = supabase.createClient(SUPABASE_URL, SUPABASE_KEY);

// --- Database Layer (Modified for Supabase) ---
const DB = {
    //  Centralised Cache for Sync Access
    cache: {},

    //  Centralised Table Mapping (Scaleable)
    mapTable(alias) {
        const map = {
            'salesorders': 'sales_orders',
            'purchaseorders': 'purchase_orders',
            'staffmaster': 'staff',
            'attendance': 'attendance',
            'hrpayroll': 'salary_records',
            'salaryadvances': 'salary_advances',
            'customerregistrations': 'customer_registrations',
            'customerotps': 'customer_otps',
            'partyledger': 'party_ledger',
            'stockledger': 'stock_ledger'
        };
        const normalized = alias.toLowerCase().replace(/[-_]/g, '');
        return map[alias] || map[normalized] || alias;
    },

    // IndexedDB native wrapper for unlimited offline storage
    idb: {
        db: null,
        init() {
            return new Promise((resolve, reject) => {
                const req = indexedDB.open('DistroDB', 1);
                req.onupgradeneeded = e => {
                    if (!e.target.result.objectStoreNames.contains('store')) e.target.result.createObjectStore('store');
                };
                req.onsuccess = e => { this.db = e.target.result; resolve(); };
                req.onerror = () => reject(req.error);
            });
        },
        async get(key) {
            if (!this.db) await this.init();
            return new Promise((resolve, reject) => {
                const req = this.db.transaction('store', 'readonly').objectStore('store').get(key);
                req.onsuccess = () => resolve(req.result);
                req.onerror = () => reject(req.error);
            });
        },
        async set(key, val) {
            if (!this.db) await this.init();
            return new Promise((resolve, reject) => {
                const req = this.db.transaction('store', 'readwrite').objectStore('store').put(val, key);
                req.onsuccess = () => resolve();
                req.onerror = () => reject(req.error);
            });
        }
    },

    async loadCacheFromIDB() {
        try {
            await this.idb.init();
            const keys = ['db_users', 'db_categories', 'db_uom', 'db_company', 'db_tax_settings', 'db_parties', 'db_inventory', 'db_sales_orders', 'db_invoices', 'db_payments', 'db_expenses', 'db_party_ledger', 'db_stock_ledger', 'db_packers', 'db_delivery_persons', 'db_delivery'];
            await Promise.all(keys.map(async k => {
                const val = await this.idb.get(k);
                if (val) {
                    this.cache[k] = val;
                    this.cache[this.mapTable(k.replace(/^db_/, ''))] = val;
                }
            }));
        } catch (e) { console.error('IDB load error', e); }
    },

    // Hybrid ls helper (now backed by in-memory + optional IDB persistence)
    ls: {
        get(key) {
            if (DB.cache[key]) return DB.cache[key];
            const mapped = DB.mapTable(key.replace(/^db_/, ''));
            if (DB.cache[mapped]) return DB.cache[mapped];
            try { return JSON.parse(localStorage.getItem(key)) || []; } catch (e) { return []; }
        },
        getObj(key) {
            if (DB.cache[key]) return DB.cache[key];
            const mapped = DB.mapTable(key.replace(/^db_/, ''));
            if (DB.cache[mapped]) return DB.cache[mapped];
            try { return JSON.parse(localStorage.getItem(key)) || {}; } catch (e) { return {}; }
        },
        set(key, data) {
            DB.cache[key] = data;
            const mapped = DB.mapTable(key.replace(/^db_/, ''));
            DB.cache[mapped] = data;

            DB.idb.set(key, data).catch(console.error);

            if (typeof data === 'object' && !Array.isArray(data) && JSON.stringify(data).length < 50000) {
                try { localStorage.setItem(key, JSON.stringify(data)); } catch (e) { }
            }
        }
    },
    async refresh() {
        // Core tables needed for Login & Dashboard basic structure
        const coreTables = ['users', 'categories', 'uom'];
        // Batch 1: high-priority tables needed for first page render
        const batch1 = ['parties', 'inventory', 'sales_orders', 'invoices', 'payments'];
        // Batch 2: lower-priority tables loaded after a short delay
        const batch2 = ['expenses', 'packers', 'delivery_persons', 'delivery'];
        // Ledger tables: load with date filter (last 6 months) to avoid huge payloads
        const ledgerCutoff = new Date(); ledgerCutoff.setMonth(ledgerCutoff.getMonth() - 6);
        const ledgerDateFrom = ledgerCutoff.toISOString().split('T')[0];

        // Mark last refresh time
        this.cache._lastRefresh = Date.now();

        // 1. Pre-load local cache from IndexedDB so offline mode responds instantly
        await this.loadCacheFromIDB();

        // 2. Load settings and core tables FIRST - block the boot sequence for these
        try {
            const [settings, ...coreResults] = await Promise.all([
                this.loadSettings(),
                ...coreTables.map(t => supabaseClient.from(t).select('*'))
            ]);
            coreResults.forEach((res, i) => {
                if (res.error) console.error(`Core table load error (${coreTables[i]}):`, res.error);
                else {
                    const camelData = this._toCamel(res.data || []);
                    this.cache[coreTables[i]] = camelData;
                    this.idb.set('db_' + coreTables[i], camelData).catch(console.error);
                }
            });
        } catch (e) { console.error('Core Refresh Error:', e); }

        const _bgLoad = (actualTable, query) => {
            Promise.resolve(query).then(res => {
                if (!res || res.error) { console.warn(`Bg Refresh Error ${actualTable}:`, res?.error?.message || 'unknown'); return; }
                const camel = this._toCamel(res.data || []);
                this.cache[actualTable] = camel;
                this.idb.set('db_' + actualTable, camel).catch(console.error);
                // Only trigger silent re-render on safe read-only pages — never during active form editing
                const safePages = ['salesorders', 'invoices', 'payments', 'parties', 'inventory', 'delivery', 'catalog', 'dashboard'];
                const isFormActive = document.querySelector('.sub-modal.active') !== null
                    || document.querySelector('#modal-overlay:not(.hidden)') !== null;
                const isCatalog = currentPage === 'catalog';
                const needsRefresh = !isFormActive && (
                    currentPage === actualTable
                    || (actualTable === 'sales_orders' && currentPage === 'salesorders')
                    || (isCatalog && (actualTable === 'sales_orders' || actualTable === 'inventory' || actualTable === 'parties'))
                );
                if (needsRefresh && safePages.includes(currentPage)) {
                    clearTimeout(this._bgNavTimer);
                    this._bgNavTimer = setTimeout(() => {
                        // Double-check a modal/form didn't open in the 500ms gap
                        const stillSafe = !document.querySelector('.sub-modal.active')
                            && !document.querySelector('#modal-overlay:not(.hidden)');
                        if (stillSafe) navigateTo(currentPage, { silent: true });
                    }, 500);
                }
                if (actualTable === 'invoices' || actualTable === 'sales_orders') {
                    if (this.cache['invoices'] && this.cache['sales_orders']) repairCancelledInvoiceOrders();
                }
            }).catch(err => {
                console.warn(`Bg load failed (${actualTable}): ${err.message}`);
            });
        };

        // Helper: wrap query with 20s timeout to prevent hanging
        const withT = (q) => Promise.race([q, new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), 20000))]);

        // 3. Batch 1: fire immediately (most-needed tables)
        batch1.forEach(t => _bgLoad(this.mapTable(t), withT(supabaseClient.from(this.mapTable(t)).select('*'))));

        // 4. Batch 2: fire after 2s delay so batch1 gets bandwidth priority
        setTimeout(() => {
            batch2.forEach(t => _bgLoad(this.mapTable(t), withT(supabaseClient.from(this.mapTable(t)).select('*'))));
        }, 2000);

        // 5. Ledger tables: load last 6 months only (unbounded = very slow on large data)
        setTimeout(() => {
            _bgLoad('party_ledger', withT(supabaseClient.from('party_ledger').select('*').gte('date', ledgerDateFrom).order('date', { ascending: false })));
            _bgLoad('stock_ledger', withT(supabaseClient.from('stock_ledger').select('*').gte('date', ledgerDateFrom).order('date', { ascending: false })));
        }, 4000);

        // gps_logs: NOT auto-loaded — fetch on demand in GPS admin view only

        // Legacy map for what we have so far
        this.cache['db_users'] = this.cache['users'] || [];
        this.cache['db_categories'] = this.cache['categories'] || [];
        this.cache['db_uom'] = this.cache['uom'] || [];

        // 3. Setup Auto-Sync (every 5 minutes or when tab becomes visible)
        if (!this._syncInit) {
            this._syncInit = true;
            setInterval(() => this.backgroundSync(), 10 * 60 * 1000); // 10 min (was 5 — too aggressive on mobile)
            window.addEventListener('visibilitychange', () => {
                if (document.visibilityState === 'visible' && (Date.now() - this.cache._lastRefresh > 5 * 60 * 1000)) {
                    console.log('Tab visible, refreshing data (stale > 5 min)...');
                    this.backgroundSync();
                }
            });
        }
    },

    backgroundSync: async function () {
        // Guard: only one sync at a time
        if (this._bgSyncing) { console.log('Background sync already running, skipping.'); return; }
        this._bgSyncing = true;
        console.log('Running background sync...');
        try {
            const tables = ['sales_orders', 'invoices', 'payments', 'inventory', 'parties'];
            const success = await this.refreshTables(tables);
            if (success) {
                this.cache._lastRefresh = Date.now();
                console.log('Background sync completed.');
            }
        } catch (e) {
            console.warn('Background sync error:', e.message);
        } finally {
            this._bgSyncing = false;
        }
    },

    async refreshTables(tableList) {
        // Wrap each query with a 15-second timeout so a hanging request doesn't freeze the app
        const withTimeout = (promise, ms = 15000) => {
            const t = new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), ms));
            return Promise.race([promise, t]);
        };
        const results = await Promise.allSettled(
            tableList.map(t => withTimeout(supabaseClient.from(this.mapTable(t)).select('*')))
        );
        let allSuccess = true;
        results.forEach((result, i) => {
            if (result.status === 'rejected') {
                console.warn(`Bg refresh timeout/error (${tableList[i]}):`, result.reason?.message);
                allSuccess = false;
                return;
            }
            const res = result.value;
            if (res.error) {
                console.error(`Error refreshing ${tableList[i]}:`, res.error);
                allSuccess = false;
                return;
            }
            const actual = this.mapTable(tableList[i]);
            const camelData = this._toCamel(res.data || []);
            this.cache[actual] = camelData;
            this.idb.set('db_' + actual, camelData).catch(console.error);
        });
        return allSuccess;
    },

    get(key) {
        const actual = this.mapTable(key.replace(/^db_/, ''));
        if (this.cache[actual]) return this.cache[actual];
        if (this.cache[key]) return this.cache[key];
        return this.ls.get(key);
    },
    getObj(key) {
        const actual = this.mapTable(key.replace(/^db_/, ''));
        if (this.cache[actual]) return this.cache[actual];
        if (this.cache[key]) return this.cache[key];
        return this.ls.getObj(key);
    },
    set(key, data) { return this.ls.set(key, data); },

    // Security: Set session context for Supabase RLS
    async setSecureSession(user) {
        if (!user) return;
        try {
            await supabaseClient.rpc('set_session_role', {
                user_role: user.role,
                user_id: (user.userId || user.id || '').toLowerCase()
            });
        } catch (e) {
            console.warn('setSecureSession error (Ensure RPC is installed):', e.message);
        }
    },

    // New Async Supabase methods with Auto Mapping
    _toSnake(obj) {
        if (!obj || typeof obj !== 'object') return obj;
        if (Array.isArray(obj)) return obj.map(v => this._toSnake(v));
        const res = {};
        for (const key in obj) {
            const snake = key.replace(/[A-Z]/g, letter => `_${letter.toLowerCase()}`);
            res[snake] = obj[key];
        }
        return res;
    },
    _toCamel(obj) {
        if (!obj || typeof obj !== 'object') return obj;
        if (Array.isArray(obj)) return obj.map(v => this._toCamel(v));
        const res = {};
        for (const key in obj) {
            const camel = key.replace(/([-_][a-z])/ig, ($1) => $1.toUpperCase().replace('-', '').replace('_', ''));
            let val = obj[key];

            // 🚀 FIX: Global safety net to catch and parse corrupted JSON strings from the DB
            if (typeof val === 'string' && ['items', 'packed_items', 'allocations', 'price_tiers', 'batches', 'package_numbers', 'cannot_complete_lines', 'sub_categories'].includes(key)) {
                try {
                    const parsed = JSON.parse(val);
                    if (typeof parsed === 'object' && parsed !== null) val = parsed;
                } catch (e) { } // Silently ignore if it's just normal text
            }

            // Recursively convert nested objects and arrays (fixes JSONB fields like batches, priceTiers, items)
            if (val && typeof val === 'object') val = this._toCamel(val);

            res[camel] = val;
        }
        return res;
    },

    // Show skeleton loaders in a container
    showSkeleton(containerId, rows = 5) {
        const el = typeof containerId === 'string' ? document.getElementById(containerId) : containerId;
        if (!el) return;
        let html = '<div style="padding:20px">';
        for (let i = 0; i < rows; i++) {
            html += '<div class="skeleton skeleton-card"></div>';
        }
        html += '</div>';
        el.innerHTML = html;
    },

    // Convert empty strings to null for date/numeric columns so Postgres doesn't choke
    _clean(obj) {
        if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return obj;
        const res = {};
        for (const key in obj) {
            const v = obj[key];
            res[key] = (v === '' && (key.includes('date') || key.includes('at') || key.includes('_at') || key === 'item_code' || key === 'party_code' || key === 'group')) ? null : v;
        }
        return res;
    },

    async getAll(table) {
        const actualTable = this.mapTable(table);
        // Return from cache if available (populated by background refresh)
        if (this.cache[actualTable] && this.cache[actualTable].length > 0) return this.cache[actualTable];
        // For large ledger/log tables use date filter to avoid fetching all-time data
        let query = supabaseClient.from(actualTable).select('*');
        if (actualTable === 'party_ledger' || actualTable === 'stock_ledger') {
            const cutoff = new Date(); cutoff.setMonth(cutoff.getMonth() - 6);
            query = query.gte('date', cutoff.toISOString().split('T')[0]).order('date', { ascending: false });
        } else if (actualTable === 'gps_logs') {
            const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 7);
            query = query.gte('timestamp', cutoff.toISOString()).order('timestamp', { ascending: false }).limit(500);
        }
        const { data, error } = await query;
        if (error) {
            console.warn(`Offline or Error fetching ${actualTable}. Falling back to IDB Cache.`);
            return this.get(actualTable) || [];
        }
        const camelData = this._toCamel(data) || [];
        this.cache[actualTable] = camelData;
        this.idb.set('db_' + actualTable, camelData).catch(console.error);
        return camelData;
    },

    async insert(table, row) {
        const actualTable = this.mapTable(table);
        const { data, error } = await supabaseClient.from(actualTable).insert(this._clean(this._toSnake(row))).select();
        if (error) { console.error(`Error inserting into ${actualTable}:`, error.message, '| sent:', JSON.stringify(this._toSnake(row))); throw error; }
        await this.refreshTables([actualTable]);
        return this._toCamel(data[0]);
    },

    async update(table, id, row) {
        const actualTable = this.mapTable(table);
        const { data, error } = await supabaseClient.from(actualTable).update(this._clean(this._toSnake(row))).eq('id', id).select();
        if (error) { console.error(`Error updating ${actualTable}:`, error.message, '| sent:', JSON.stringify(this._toSnake(row))); throw error; }
        // Immediately patch the specific item in cache so UI reflects changes without waiting for refreshTables
        const updatedItem = data && data.length > 0 ? this._toCamel(data[0]) : { id, ...this._toCamel(row) };
        if (this.cache[actualTable]) {
            const idx = this.cache[actualTable].findIndex(x => x.id === id);
            if (idx >= 0) this.cache[actualTable][idx] = { ...this.cache[actualTable][idx], ...updatedItem };
            else this.cache[actualTable].push(updatedItem);
        }
        await this.refreshTables([actualTable]);
        return updatedItem;
    },

    async delete(table, id) {
        const actualTable = this.mapTable(table);

        const record = (await this.getAll(actualTable)).find(r => r.id === id);
        if (!record) throw new Error('Record not found');

        // 🔴 BLOCK DELETE IF POSTED — only for core documents that require a Cancel reversal workflow
        const CANCEL_ONLY_TABLES = ['invoices', 'sales_orders', 'purchase_orders'];
        if (record.status === 'posted' && CANCEL_ONLY_TABLES.includes(actualTable)) {
            throw new Error('Cannot delete posted document. Use Cancel.');
        }

        const { error } = await supabaseClient
            .from(actualTable)
            .delete()
            .eq('id', id);

        if (error) throw error;

        await this.refreshTables([actualTable]);
    },

    // 🔑 Admin Delete — uses SECURITY DEFINER RPC to bypass RLS in a single transaction
    async adminDelete(table, id) {
        const actualTable = this.mapTable(table);
        const role = (currentUser && currentUser.role) || 'Unknown';
        const { error } = await supabaseClient.rpc('admin_delete_record', {
            p_table: actualTable,
            p_id: id,
            p_user_role: role
        });
        if (error) throw error;
        await this.refreshTables([actualTable]);
    },

    // 🔑 Admin Update — uses SECURITY DEFINER RPC to bypass RLS in a single transaction
    async adminUpdate(table, id, row) {
        const actualTable = this.mapTable(table);
        const role = (currentUser && currentUser.role) || 'Unknown';
        const snakeRow = this._clean(this._toSnake(row));
        const { error } = await supabaseClient.rpc('admin_update_record', {
            p_table: actualTable,
            p_id: id,
            p_data: snakeRow,
            p_user_role: role
        });
        if (error) throw error;
        await this.refreshTables([actualTable]);
        return { id };
    },

    //  Raw operations  NO auto-refresh (batch multiple then call DB.refresh() once) 
    async rawUpdate(table, id, row) {
        const actualTable = this.mapTable(table);
        const { data, error } = await supabaseClient.from(actualTable).update(this._clean(this._toSnake(row))).eq('id', id).select();
        if (error) { console.error(`rawUpdate ${actualTable}:`, error.message); throw error; }
        // Note: data may be empty if RLS SELECT policy doesn't return the row — update still succeeded if no error
    },
    async rawInsert(table, row) {
        const actualTable = this.mapTable(table);
        const { data, error } = await supabaseClient.from(actualTable).insert(this._clean(this._toSnake(row))).select();
        if (error) { console.error(`rawInsert ${actualTable}:`, error.message); throw error; }
        return this._toCamel(data[0]);
    },

    //  Settings: persisted in Supabase `settings` table AND localStorage 
    async saveSettings(key, data) {
        this.ls.set(key, data); // always update local immediately
        try {
            const { error } = await supabaseClient.from('settings').upsert({ key, value: data }, { onConflict: 'key' });
            if (error) {
                console.warn('saveSettings cloud error:', error.message);
                // Show warning if it looks like table is missing or permission denied
                if (error.code === '42P01' || error.message?.includes('does not exist')) {
                    showToast(' Cloud sync failed: settings table missing. Run schema.sql in Supabase.', 'error');
                }
            }
        } catch (e) { console.warn('saveSettings error:', e); }
    },
    async loadSettings() {
        try {
            const { data, error } = await supabaseClient.from('settings').select('*');
            if (error) { console.warn('loadSettings cloud error:', error.message); return; }
            if (data && data.length > 0) {
                data.forEach(row => { this.ls.set(row.key, row.value); });
            }
        } catch (e) { console.warn('loadSettings error:', e); }
    },


    // --- SECURITY & PERMISSIONS ---
    // Check if current user can edit/delete records (Admin only by default)
    canEdit() {
        if (!window.currentUser) return false;
        if (window.currentUser.role === 'Admin') return true;
        return !!window.currentUser.canEdit; // Check custom per-user permission
    },

    // Check if user can post to a back-date (Admin only)
    canPostBackDate(dateStr) {
        // Use the local currentUser variable which is the source of truth
        const u = currentUser;
        if (!u) return false;

        // Robust role checking
        const roles = (Array.isArray(u.roles) ? u.roles : [u.role]).map(r => (r || '').toLowerCase());
        const isAdmin = roles.some(r => r === 'admin' || r === 'administrator' || r === 'owner' || r === 'manager');

        if (isAdmin) return true;

        const todayStr = today();
        return dateStr >= todayStr;
    },

    // --- EXPORT TO EXCEL ---
    exportToExcel(tableId, filename = 'export') {
        const tbl = document.getElementById(tableId);
        if (!tbl) return alert('Table not found for export');
        try {
            const wb = XLSX.utils.table_to_book(tbl, { sheet: "Sheet1" });
            XLSX.writeFile(wb, `${filename}_${new Date().toISOString().split('T')[0]}.xlsx`);
        } catch (e) {
            console.error('Excel Export Error:', e);
            alert('Failed to export to Excel. Please try again.');
        }
    },

    id() {
        if (typeof crypto !== 'undefined' && crypto.randomUUID) return crypto.randomUUID();
        return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
            var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
            return v.toString(16);
        });
    }
};

