// --- Helpers ---
function compressImage(file, { maxWidth = 1024, maxHeight = 1024, quality = 0.75 } = {}) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = e => {
            const img = new Image();
            img.src = e.target.result;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;

                if (width > height) {
                    if (width > maxWidth) {
                        height *= maxWidth / width;
                        width = maxWidth;
                    }
                } else {
                    if (height > maxHeight) {
                        width *= maxHeight / height;
                        height = maxHeight;
                    }
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', quality));
            };
            img.onerror = reject;
        };
        reader.onerror = reject;
    });
}

function currency(n) { return '' + (+n || 0).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 }); }
function fmtDate(d) { return d ? new Date(d).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : '-'; }
function today() {
    const d = new Date();
    // Correct for local timezone offset to get local YYYY-MM-DD
    const offset = d.getTimezoneOffset() * 60000;
    return new Date(d.getTime() - offset).toISOString().split('T')[0];
}
function isSalesman() {
    const r = (currentUser?.role || '').toLowerCase();
    return r === 'salesman';
}
function isPacker() {
    const r = (currentUser?.role || '').toLowerCase();
    return r === 'packing' || r === 'packer';
}
function canEdit() {
    const r = (currentUser?.role || '').toLowerCase();
    return r === 'admin' || r === 'administrator' || r === 'manager';
}
function canViewLedger() {
    const r = (currentUser?.role || '').toLowerCase();
    if (r === 'admin' || r === 'administrator' || r === 'manager') return true;
    return Array.isArray(currentUser?.extra_perms) && currentUser.extra_perms.includes('partyledger');
}

