function toggleSoFilters() {
    const extra = $('so-extra-filters');
    const btn = $('so-filter-toggle');
    if (!extra) return;
    const open = extra.style.display !== 'none';
    extra.style.display = open ? 'none' : 'block';
    if (btn) {
        btn.style.background = open ? 'var(--bg-input)' : 'var(--primary)';
        btn.style.color = open ? '' : '#fff';
    }
}
function renderSoCards(orders, isApprover) {
    if (!orders.length) return `<div style="text-align:center;padding:40px 20px;color:var(--text-muted)"><div style="font-size:2rem;margin-bottom:8px"></div><div>No orders found</div></div>`;
    return orders.map(o => {
        const disp = getOrderDisplayStatusSync(o);
        const isUrgent = o.isUrgent;
        const delDate = o.expectedDeliveryDate ? `<span style="font-size:0.75rem;color:${new Date(o.expectedDeliveryDate) < new Date() && o.status !== 'delivered' ? 'var(--danger)' : 'var(--text-muted)'}">Delivery: ${fmtDate(o.expectedDeliveryDate)}</span>` : '';
        return `<div data-so-id="${o.id}" style="background:var(--bg-card);border:1px solid var(--border);${isUrgent ? 'border-left:3px solid var(--danger);' : ''}border-radius:12px;padding:12px 14px;margin-bottom:10px;box-shadow:0 1px 4px rgba(0,0,0,0.05);position:relative" onclick="viewSalesOrder('${o.id}')">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px">
                <div style="display:flex;flex-direction:column;gap:2px;flex:1;min-width:0;padding-right:8px">
                    <div style="font-weight:700;font-size:1rem;color:var(--text-primary);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml(o.partyName)}</div>
                    <div style="font-size:0.75rem;color:var(--text-muted)">#${o.orderNo} · ${fmtDate(o.date)}</div>
                </div>
                <div style="text-align:right">
                    <div style="font-size:1.1rem;font-weight:800;color:var(--text-primary)">${currency(o.total)}</div>
                    <div style="font-size:0.7rem;color:var(--text-muted)">Total</div>
                </div>
            </div>
            <div style="display:flex;justify-content:space-between;align-items:center;margin-top:8px;padding-top:8px;border-top:1px solid var(--border)">
                <div style="display:flex;flex-direction:column;gap:2px">
                    <span class="badge ${disp.class}" style="font-size:0.65rem;padding:2px 6px;text-transform:capitalize;align-self:flex-start">${disp.text}${isUrgent ? ' (URGENT)' : ''}</span>
                    ${delDate}
                </div>
                <div style="display:flex;gap:4px;align-items:center" onclick="event.stopPropagation()">
                    ${o.status === 'pending' && isApprover ? `<button class="btn-icon" style="color:var(--success)" onclick="approveSalesOrder('${o.id}')" title="Approve"><span class="material-symbols-outlined" style="font-size:1.1rem">check_circle</span></button>` : ''}
                    ${o.status === 'pending' && isApprover ? `<button class="btn-icon" style="color:var(--danger)" onclick="rejectSalesOrder('${o.id}')" title="Reject"><span class="material-symbols-outlined" style="font-size:1.1rem">cancel</span></button>` : ''}
                    <button class="btn btn-outline btn-sm" style="padding:4px 8px;font-size:0.75rem;border-radius:6px" onclick="duplicateSalesOrder('${o.id}')">Duplicate</button>
                    ${(o.status === 'pending' || (o.status === 'approved' && !o.packed && !o.invoiceNo)) && isApprover ? `<button class="btn btn-outline btn-sm" style="padding:4px 8px;font-size:0.75rem;border-radius:6px" onclick="editSalesOrder('${o.id}')">Edit</button>` : ''}
                </div>
            </div>
        </div>`;
    }).join('');
}
function getOrderDisplayStatusSync(o) {
    if (o.status !== 'approved') return { text: o.status, class: o.status === 'rejected' ? 'badge-danger' : 'badge-warning' };
    if (!o.packed && !o.invoiceNo) return { text: 'approved', class: 'badge-success' };
    const dels = (DB.cache['delivery'] || []).filter(d => d.orderNo === o.orderNo);
    let deliveryStatus = null;
    if (dels.length > 0) {
        const activeDel = dels.find(d => d.status !== 'Cancelled') || dels[dels.length - 1];
        deliveryStatus = activeDel.status;
    }
    if (o.invoiceNo) {
        const inv = (DB.cache['invoices'] || []).find(i => i.invoiceNo === o.invoiceNo);
        if (inv && inv.status === 'cancelled') return { text: 'returned/cancelled', class: 'badge-danger' };
    }
    if (deliveryStatus === 'Delivered') return { text: 'Delivered', class: 'badge-success' };
    if (deliveryStatus === 'Dispatched') return { text: 'Dispatched', class: 'badge-info' };
    if (deliveryStatus === 'Undelivered') return { text: 'Undelivered', class: 'badge-warning' };
    if (deliveryStatus === 'Returned') return { text: 'Returned', class: 'badge-danger' };
    if (o.invoiceNo) return { text: 'Invoiced', class: 'badge-success' };
    if (o.packed) return { text: 'Packed', class: 'badge-success' };
    return { text: 'approved', class: 'badge-success' };
}
async function getOrderDisplayStatus(o) {
    if (o.status !== 'approved') return { text: o.status, class: o.status === 'rejected' ? 'badge-danger' : 'badge-warning' };

    // It's approved. Let's trace it downstream.
    if (!o.packed && !o.invoiceNo) return { text: 'approved', class: 'badge-success' };

    // Check delivery records
    let deliveryStatus = null;
    if (o.invoiceNo) {
        const dels = (await DB.getAll('delivery')).filter(d => d.orderNo === o.orderNo);
        if (dels.length > 0) {
            const activeDel = dels.find(d => d.status !== 'Cancelled') || dels[dels.length - 1];
            deliveryStatus = activeDel.status;
        }
    }

    // Check if the associated invoice was cancelled completely
    if (o.invoiceNo) {
        const invoices = await DB.getAll('invoices');
        const inv = invoices.find(i => i.invoiceNo === o.invoiceNo);
        if (inv && inv.status === 'cancelled') {
            return { text: 'returned/cancelled', class: 'badge-danger' };
        }
    }

    if (deliveryStatus === 'Delivered') return { text: 'Delivered', class: 'badge-success' };
    if (deliveryStatus === 'Dispatched') return { text: 'Dispatched', class: 'badge-info' };
    if (deliveryStatus === 'Undelivered') return { text: 'Undelivered', class: 'badge-warning' };
    if (deliveryStatus === 'Returned') return { text: 'Returned', class: 'badge-danger' };

    if (o.invoiceNo) return { text: 'Invoiced', class: 'badge-success' };
    if (o.packed) return { text: 'Packed', class: 'badge-success' };

    return { text: 'approved', class: 'badge-success' };
}

function renderSORows(orders, isApprover) {
    if (!orders.length) return '<tr><td colspan="10" class="empty-state"><p>No orders found</p></td></tr>';
    const cols = ColumnManager.get('salesorders').filter(c => c.visible);
    return orders.map(o => {
        const disp = getOrderDisplayStatusSync(o);
        const isUrgent = o.isUrgent;
        const delDate = o.expectedDeliveryDate ? `<span style="font-size:0.8rem;color:${new Date(o.expectedDeliveryDate) < new Date() && o.status !== 'delivered' ? 'var(--danger)' : 'var(--text-muted)'}">${fmtDate(o.expectedDeliveryDate)}</span>` : '-';
        const chkTd = isApprover ? `<td><input type="checkbox" class="so-select-chk" data-id="${o.id}" onchange="soUpdateBulkBtn()" style="width:16px;height:16px"></td>` : '<td></td>';
        const cellMap = {
            date: `<td style="min-width:90px">${fmtDate(o.date)}</td>`,
            orderNo: `<td style="min-width:100px;font-weight:600">${o.orderNo}${isUrgent ? ' <span class="badge badge-danger" style="font-size:0.6rem"></span>' : ''}</td>`,
            party: `<td style="min-width:150px;max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(o.partyName)}</td>`,
            delivery: `<td style="min-width:100px">${delDate}</td>`,
            items: `<td style="min-width:50px;text-align:center">${o.items.length}</td>`,
            total: `<td style="min-width:100px;text-align:right" class="amount-green">${currency(o.total)}</td>`,
            by: `<td style="min-width:100px;font-size:0.82rem">${o.createdBy || '-'}</td>`,
            status: `<td style="min-width:120px"><span class="badge ${disp.class}" style="text-transform:capitalize">${disp.text}</span></td>`,
            actions: `<td style="min-width:140px"><div class="action-btns">
                <button class="btn-icon" onclick="viewSalesOrder('${o.id}')" title="View"><span class="material-symbols-outlined" style="font-size:1.1rem">visibility</span></button>
                <button class="btn-icon" onclick="duplicateSalesOrder('${o.id}')" title="Duplicate"><span class="material-symbols-outlined" style="font-size:1.1rem">content_copy</span></button>
                ${o.status === 'pending' && isApprover ? `<button class="btn-icon" style="color:var(--success)" onclick="approveSalesOrder('${o.id}')" title="Approve"><span class="material-symbols-outlined" style="font-size:1.1rem">check_circle</span></button><button class="btn-icon" style="color:var(--danger)" onclick="rejectSalesOrder('${o.id}')" title="Reject"><span class="material-symbols-outlined" style="font-size:1.1rem">cancel</span></button>` : ''}
                ${(o.status === 'pending' || (o.status === 'approved' && !o.packed && !o.invoiceNo)) && isApprover ? `<button class="btn-icon" style="color:var(--warning)" onclick="editSalesOrder('${o.id}')" title="Edit"><span class="material-symbols-outlined" style="font-size:1.1rem">edit</span></button>` : ''}
                ${o.status === 'pending' && canEdit() ? `<button class="btn-icon" onclick="deleteSalesOrder('${o.id}')" title="Delete" style="color:var(--danger)"><span class="material-symbols-outlined" style="font-size:1.1rem">delete</span></button>` : ''}
            </div></td>`,
        };
        return `<tr${isUrgent ? ' style="background:rgba(239,68,68,0.06);border-left:3px solid var(--danger)"' : ''}>${chkTd}${cols.map(c => cellMap[c.key] || '').join('')}</tr>`;
    }).join('');
}
function soToggleAll(checked) {
    document.querySelectorAll('.so-select-chk').forEach(c => { c.checked = checked; });
    soUpdateBulkBtn();
}
function soUpdateBulkBtn() {
    const checked = document.querySelectorAll('.so-select-chk:checked');
    const btn = $('btn-bulk-approve');
    const cnt = $('bulk-approve-count');
    if (btn) { btn.style.display = checked.length > 0 ? '' : 'none'; }
    if (cnt) cnt.textContent = checked.length;
    // Sync select-all checkbox state
    const all = document.querySelectorAll('.so-select-chk');
    const selAll = $('so-select-all');
    if (selAll && all.length > 0) selAll.checked = all.length === checked.length;
}
async function bulkApproveOrders() {
    const checked = [...document.querySelectorAll('.so-select-chk:checked')];
    if (!checked.length) return;
    if (!confirm(`Approve ${checked.length} selected order(s)?`)) return;
    const ids = checked.map(c => c.dataset.id);
    await Promise.all(ids.map(id => DB.update('salesorders', id, { status: 'approved' })));
    showToast(`${ids.length} order(s) approved!`, 'success');
    renderSalesOrders();
}
async function filterSOTable() {
    const s = $('so-search').value.toLowerCase(), st = $('so-status-filter').value;
    const pf = $('so-priority-filter') ? $('so-priority-filter').value : '';
    const sort = $('so-sort') ? $('so-sort').value : 'date-desc';
    let orders = await DB.getAll('salesorders');
    if (s) orders = orders.filter(o => o.orderNo.toLowerCase().includes(s) || o.partyName.toLowerCase().includes(s));
    if (st) orders = orders.filter(o => o.status === st);
    if (pf) orders = orders.filter(o => (o.priority || 'Normal') === pf);
    // Sorting
    const statusRank = o => {
        if (o.status === 'pending') return 0;
        if (o.status === 'approved' && !o.packed && !o.invoiceNo) return 1;
        if (o.packed && !o.invoiceNo) return 2;
        if (o.invoiceNo) return 3;
        if (o.status === 'rejected') return 4;
        if (o.status === 'cancelled') return 5;
        return 6;
    };
    orders.sort((a, b) => {
        const rankDiff = statusRank(a) - statusRank(b);
        if (rankDiff !== 0) return rankDiff;
        if (sort === 'date-asc') return (a.date || '').localeCompare(b.date || '');
        if (sort === 'date-desc') return (b.date || '').localeCompare(a.date || '');
        if (sort === 'delivery-asc') return (a.expectedDeliveryDate || '9999').localeCompare(b.expectedDeliveryDate || '9999');
        if (sort === 'delivery-desc') return (b.expectedDeliveryDate || '').localeCompare(a.expectedDeliveryDate || '');
        return (b.date || '').localeCompare(a.date || '');
    });
    const isApprover = currentUser.role === 'Admin' || currentUser.role === 'Manager';
    const isMobile = window.innerWidth < 768;
    if (isMobile) {
        if ($('so-list')) $('so-list').innerHTML = renderSoCards(orders, isApprover);
    } else {
        if ($('so-tbody')) $('so-tbody').innerHTML = renderSORows(orders, isApprover);
    }
    soUpdateBulkBtn();
}
