async function saveEditedInvoice(id) {
    if (!canEdit()) return alert('Access Denied');
    if (!beginSave()) return;
    if (!invoiceItems.length) { endSave(); return alert('Invoice must have at least one item.'); }

    try {
        const [invoices, inventory, parties, expenses] = await Promise.all([
            DB.getAll('invoices'), DB.getAll('inventory'), DB.getAll('parties'), DB.getAll('expenses')
        ]);
        const inv = invoices.find(i => i.id === id);
        if (!inv) { endSave(); return alert('Invoice not found.'); }
        if (inv.status === 'cancelled') { endSave(); return alert('Cannot edit a cancelled invoice.'); }

        const party = parties.find(p => p.id === inv.partyId);
        const gst = +($('f-inv-gst')?.value || 0);
        const discPct = +($('f-inv-disc-pct')?.value || 0);
        const discAmt = +($('f-inv-disc-amt')?.value || 0);
        const roundOff = +($('f-inv-roundoff')?.value || 0);
        const sub = invoiceItems.reduce((s, li) => s + li.amount, 0);
        const newTotal = Math.max(0, +(sub + roundOff - discAmt).toFixed(2));
        const oldTotal = inv.total;

        const ops = [];

        // 1. Reverse original stock effects (including batch qty restoration)
        for (const li of (inv.items || [])) {
            const item = inventory.find(x => x.id === li.itemId);
            if (!item) continue;
            const effectiveQty = li.packedQty !== undefined ? li.packedQty : li.qty;
            const reverseQty = effectiveQty; // restore sold qty back to stock
            item.stock = (item.stock || 0) + reverseQty;
            const itemUpdateReverse = { stock: item.stock };
            // Restore batch qty: add back to newest active batch (reverse of FIFO)
            if (item.batches && item.batches.length) {
                const batches = JSON.parse(JSON.stringify(item.batches));
                const active = batches.filter(b => b.isActive !== false).sort((a, b) => (a.receivedDate || '') < (b.receivedDate || '') ? -1 : 1);
                const target = active[active.length - 1] || batches[batches.length - 1];
                if (target) target.qty = (target.qty || 0) + reverseQty;
                itemUpdateReverse.batches = batches;
                Object.assign(itemUpdateReverse, syncItemPricesFromBatches(batches));
                item.batches = batches;
            }
            ops.push(DB.rawUpdate('inventory', item.id, itemUpdateReverse));
            ops.push(DB.rawInsert('stock_ledger', {
                date: inv.date, itemId: item.id, itemName: item.name,
                entryType: 'Invoice Edit Reversal', qty: reverseQty,
                runningStock: item.stock, documentNo: inv.invoiceNo,
                reason: `Edit reversal: ${inv.invoiceNo}`, createdBy: currentUser.userId
            }));
        }

        // 2. Apply new stock effects (including FIFO batch qty deduction)
        for (const li of invoiceItems) {
            const item = inventory.find(x => x.id === li.itemId);
            if (!item) continue;
            item.stock = (item.stock || 0) - li.qty;
            const itemUpdateNew = { stock: item.stock };
            if (item.batches && item.batches.length) {
                const batchResult = deductBatchQtyFifo(item, li.qty);
                if (batchResult && batchResult.updatedBatches) {
                    itemUpdateNew.batches = batchResult.updatedBatches;
                    Object.assign(itemUpdateNew, batchResult.priceSync || {});
                    item.batches = batchResult.updatedBatches;
                }
            }
            ops.push(DB.rawUpdate('inventory', item.id, itemUpdateNew));
            ops.push(DB.rawInsert('stock_ledger', {
                date: inv.date, itemId: item.id, itemName: item.name,
                entryType: 'Sale', qty: -li.qty,
                runningStock: item.stock, documentNo: inv.invoiceNo,
                reason: `Edited Invoice ${inv.invoiceNo}`, createdBy: currentUser.userId
            }));
        }

        // 3. Adjust party balance (net difference)
        if (party) {
            const balDiff = newTotal - oldTotal;
            const newBal = +((party.balance || 0) + balDiff).toFixed(2);
            ops.push(DB.rawUpdate('parties', party.id, { balance: newBal }));
            if (Math.abs(balDiff) > 0.001) {
                ops.push(DB.rawInsert('party_ledger', {
                    date: inv.date, partyId: party.id, partyName: party.name,
                    type: 'Invoice Edit', amount: balDiff,
                    balance: newBal, docNo: inv.invoiceNo,
                    notes: `Invoice ${inv.invoiceNo} edited`, createdBy: currentUser.userId
                }));
            }
        }

        // 4. Update discount expense
        const oldDiscExp = expenses.find(e => e.category === 'Sales Discount' && e.docNo === inv.invoiceNo);
        if (oldDiscExp) await DB.delete('expenses', oldDiscExp.id);
        if (discAmt > 0) {
            ops.push(DB.rawInsert('expenses', {
                date: inv.date, category: 'Sales Discount', amount: discAmt,
                party_id: inv.partyId, party_name: inv.partyName, doc_no: inv.invoiceNo,
                description: `Discount on ${inv.invoiceNo} (edited)`
            }));
        }

        // 5. Update invoice
        ops.push(DB.rawUpdate('invoices', id, {
            items: [...invoiceItems],
            subtotal: sub, gst, discount_pct: discPct, discount_amt: discAmt,
            round_off: roundOff, total: newTotal
        }));

        await Promise.all(ops);

        // BUG 3: Recalculate running stock for all affected items
        const affectedItemIds = new Set();
        for (const li of (inv.items || [])) { if (li.itemId) affectedItemIds.add(li.itemId); }
        for (const li of invoiceItems) { if (li.itemId) affectedItemIds.add(li.itemId); }
        await Promise.all([...affectedItemIds].map(itemId => recalculateStockLedger(itemId)));

        await DB.refreshTables(['invoices', 'inventory', 'parties', 'expenses', 'stock_ledger', 'party_ledger']);
        closeModal();
        await renderInvoices();
        showToast(`Invoice ${inv.invoiceNo} updated successfully!`, 'success');
    } catch (err) {
        endSave();
        alert('Error saving invoice edits: ' + err.message);
    }
}

async function recalculateStockLedger(itemId) {
    try {
        const { data, error } = await supabaseClient
            .from('stock_ledger')
            .select('*')
            .eq('item_id', itemId)
            .order('date', { ascending: true })
            .order('id', { ascending: true });
        if (error || !data || !data.length) return;
        let running = 0;
        for (const entry of data) {
            running = +(running + (entry.qty || 0)).toFixed(2);
            await DB.rawUpdate('stock_ledger', entry.id, { runningStock: running });
        }
        await DB.refreshTables(['stock_ledger']);
    } catch (e) {
        console.warn('recalculateStockLedger error for item', itemId, e);
    }
}

async function openAssignCollectorModal(invId) {
    const users = await DB.getAll('users');
    const collectors = users.filter(u => ['Admin', 'Manager', 'Salesman'].includes(u.role));

    openModal('Assign Collector', `
        <div class="form-group" style="margin-bottom:20px">
            <label>Select Staff / Salesman</label>
            <select id="f-assign-collector">
                <option value="">-- Remove Assignment --</option>
                ${collectors.map(u => `<option value="${u.name}">${u.name} (${u.role})</option>`).join('')}
            </select>
        </div>
        <div class="modal-actions">
            <button class="btn btn-outline" onclick="closeModal()">Cancel</button>
            <button class="btn btn-primary" onclick="executeAssignCollector('${invId}')">Save Assignment</button>
        </div>
    `);
}

async function executeAssignCollector(invId) {
    const collector = $('f-assign-collector').value;
    const invoices = await DB.getAll('invoices');
    const inv = invoices.find(i => i.id === invId);
    if (!inv) return;

    const historyEntry = {
        date: new Date().toISOString(),
        assignedTo: collector || 'Unassigned',
        assignedBy: currentUser ? currentUser.name : 'System'
    };

    const allocationHistory = Array.isArray(inv.allocationHistory) ? inv.allocationHistory : [];
    allocationHistory.push(historyEntry);

    await DB.update('invoices', invId, { allocatedTo: collector || null, allocationHistory });
    showToast(collector ? 'Invoice assigned to ' + collector : 'Assignment removed', 'success');
    closeModal();
    if (currentPage === 'reports' && typeof window.renderCollectionAllocationsRpt === 'function') {
        // Re-fetch data and re-render the report in-place
        const freshInvoices = await DB.getAll('invoices');
        window._rAllocAll = freshInvoices.filter(i => i.type === 'sale' && i.status !== 'cancelled');
        await window.renderCollectionAllocationsRpt();
    } else if (currentPage === 'invoices') {
        renderInvoices();
    }
}

// Per-invoice cancel lock — prevents double-cancel even across modal open/close cycles
const _cancellingInvoices = new Set();

function cancelInvoiceDirectly(id) {
    const invoices = DB.cache['invoices'] || DB.get('db_invoices') || [];
    const inv = invoices.find(i => i.id === id);
    if (!inv || inv.status === 'cancelled') return alert('This invoice is already cancelled.');
    if (_cancellingInvoices.has(id)) return; // already in progress
    openModal('Cancel Invoice', `
        <div style="margin-bottom:14px;padding:12px;background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.3);border-radius:8px;font-size:0.9rem">
            <strong>Invoice:</strong> ${inv.invoiceNo}<br>
            <strong>Party:</strong> ${inv.partyName} | <strong>Amount:</strong> ${currency(inv.total)}
        </div>
        <p style="margin-bottom:16px;font-size:0.9rem">Cancel this invoice? Stock will be restored and party balance adjusted.</p>
        <div class="modal-actions"><button class="btn btn-outline" onclick="closeModal()">Keep Invoice</button>
        <button id="btn-confirm-cancel" class="btn btn-danger" onclick="executeCancelInvoice('${id}')"> Cancel Invoice</button></div>`);
}
async function executeCancelInvoice(id, { skipNav = false } = {}) {
    if (_cancellingInvoices.has(id)) return;
    // Check cache first for fast early exit before any await
    const cachedInvs = DB.cache['invoices'] || [];
    const cachedInv = cachedInvs.find(x => x.id === id);
    if (cachedInv && cachedInv.status === 'cancelled') { closeModal(); return; }
    _cancellingInvoices.add(id);
    // Disable the button immediately to prevent double-click
    const btn = document.getElementById('btn-confirm-cancel');
    if (btn) { btn.disabled = true; btn.textContent = 'Cancelling...'; }

    const invoices = await DB.getAll('invoices');
    const inv = invoices.find(i => i.id === id);
    if (!inv) { _cancellingInvoices.delete(id); closeModal(); return; }
    if (inv.status === 'cancelled') { _cancellingInvoices.delete(id); closeModal(); showToast('Invoice already cancelled.', 'warning'); return; }

    try {
        // ✅ MARK AS CANCELLED FIRST — prevents double-cancel if anything below fails
        await DB.update('invoices', id, { status: 'cancelled' });

        // Sync cache immediately — if RLS blocks SELECT the update still succeeded (no error above)
        if (Array.isArray(DB.cache['invoices'])) {
            const ci = DB.cache['invoices'].find(x => x.id === id);
            if (ci) ci.status = 'cancelled';
        }

        // ✅ LEDGER DEDUPLICATION GUARD — reliable across page refreshes & retries
        // If Sale Return entries already exist for this invoice, stock was already restored
        const existingLedger = await DB.getAll('stock_ledger');
        const alreadyRestored = existingLedger.some(e =>
            e.documentNo === inv.invoiceNo &&
            (e.entryType === 'Sale Return' || e.entryType === 'Purchase Return') &&
            e.reason === 'Invoice Cancelled'
        );
        if (alreadyRestored) {
            _cancellingInvoices.delete(id);
            closeModal();
            await renderInvoices();
            showToast('Invoice ' + inv.invoiceNo + ' was already cancelled.', 'warning');
            return;
        }

        // Restore stock
        const inventory = await DB.getAll('inventory');
        for (const li of (inv.items || [])) {
            const item = inventory.find(x => x.id === li.itemId);
            if (item) {
                // BUG-018 fix: use packedQty if available (partial packing), else fall back to qty
                const effectiveQty = li.packedQty !== undefined ? li.packedQty : li.qty;
                const qtyChange = inv.type === 'sale' ? effectiveQty : -effectiveQty;
                const newStock = (item.stock || 0) + qtyChange;
                const itemUpdate = { stock: newStock };
                // Restore batch quantities for sale cancellation (reverse FIFO)
                if (inv.type === 'sale' && item.batches && item.batches.length) {
                    const batches = JSON.parse(JSON.stringify(item.batches));
                    // Add back to the newest active batch (or last batch)
                    const active = batches.filter(b => b.isActive !== false).sort((a, b) => (a.receivedDate || '') < (b.receivedDate || '') ? -1 : 1);
                    const target = active[active.length - 1] || batches[batches.length - 1];
                    if (target) target.qty = (target.qty || 0) + effectiveQty;
                    itemUpdate.batches = batches;
                    Object.assign(itemUpdate, syncItemPricesFromBatches(batches));
                }
                await DB.update('inventory', item.id, itemUpdate);
                await addLedgerEntry(item.id, item.name, inv.type === 'sale' ? 'Sale Return' : 'Purchase Return', qtyChange, inv.invoiceNo, 'Invoice Cancelled');
            }
        }

        // Reverse party balance
        const parties = await DB.getAll('parties');
        const party = parties.find(p => p.id === inv.partyId);
        if (party) {
            const balChange = inv.type === 'sale' ? -inv.total : inv.total;
            const newBal = (party.balance || 0) + balChange;
            await DB.update('parties', party.id, { balance: newBal });
            await addPartyLedgerEntry(party.id, party.name, inv.type === 'sale' ? 'Sale Cancel' : 'Purchase Cancel', balChange, inv.invoiceNo, 'Invoice Cancelled');
        }

        // Clean up Sales Discount from Expenses to fix P&L
        if (inv.discountAmt > 0 && inv.type === 'sale') {
            const expenses = await DB.getAll('expenses');
            const exp = expenses.find(e => e.category === 'Sales Discount' && e.docNo === inv.invoiceNo);
            if (exp) await DB.delete('expenses', exp.id);
        }

        // Reset associated sales order — mark cancelled so it won't reappear in packing module
        if (inv.fromOrder) {
            const orders = await DB.getAll('salesorders');
            const order = orders.find(o => o.orderNo === inv.fromOrder);
            if (order && order.status !== 'cancelled') {
                await DB.update('salesorders', order.id, { invoiceCancelled: true, invoiceNo: null, status: 'cancelled' });
                // Patch cache immediately
                if (Array.isArray(DB.cache['salesorders'])) {
                    const co = DB.cache['salesorders'].find(x => x.id === order.id);
                    if (co) { co.invoiceCancelled = true; co.invoiceNo = null; co.status = 'cancelled'; }
                }
            }
        }

        // Auto-release any payments allocated to this invoice
        const allPayments = await DB.getAll('payments');
        for (const pay of allPayments) {
            if (!pay.allocations || !pay.allocations[inv.invoiceNo]) continue;
            const releasedAmt = pay.allocations[inv.invoiceNo];
            const newAlloc = { ...pay.allocations };
            delete newAlloc[inv.invoiceNo];
            const newInvNo = Object.keys(newAlloc).join(',') || '';
            await DB.rawUpdate('payments', pay.id, { allocations: newAlloc, invoice_no: newInvNo });
            // Reverse the balance reduction on the party for the released amount
            const payParties = await DB.getAll('parties');
            const payParty = payParties.find(p => p.id === pay.partyId);
            if (payParty) {
                const reversal = pay.type === 'in' ? releasedAmt : -releasedAmt;
                await DB.rawUpdate('parties', payParty.id, { balance: +((payParty.balance || 0) + reversal).toFixed(2) });
                await addPartyLedgerEntry(payParty.id, payParty.name, 'Payment Unallocated', reversal, pay.payNo || pay.id, `Released from cancelled invoice ${inv.invoiceNo}`);
            }
        }

        // Cancel delivery records and patch cache immediately
        const dels = await DB.getAll('delivery');
        for (const d of dels) {
            if (d.invoiceNo === inv.invoiceNo && d.status !== 'Delivered' && d.status !== 'Cancelled') {
                await DB.update('delivery', d.id, { status: 'Cancelled', cancelReason: 'Invoice cancelled' });
                if (Array.isArray(DB.cache['delivery'])) {
                    const cd = DB.cache['delivery'].find(x => x.id === d.id);
                    if (cd) cd.status = 'Cancelled';
                }
            }
        }

        _cancellingInvoices.delete(id);
        if (!skipNav) {
            closeModal();
            await renderInvoices();
        }
        showToast('Invoice ' + inv.invoiceNo + ' cancelled!', 'warning');
    } catch (err) {
        _cancellingInvoices.delete(id);
        if (!skipNav) alert('Error cancelling invoice: ' + err.message);
        throw err; // re-throw so callers (e.g. executeCancelDeliveryInvoice) can handle
    }
}
async function deleteInvoice(id) {
    if (!canEdit()) {
        return alert("Access Denied: Only Admin or users with Edit permission can delete records.");
    }
    const invoices = await DB.getAll('invoices');
    const inv = invoices.find(i => i.id === id);
    if (!inv) return;
    if (!confirm('Delete this invoice permanently? Effects will be reversed.')) return;

    try {
        const inv = (await DB.getAll('invoices')).find(r => r.id === id);
        if (!inv) throw new Error('Invoice not found');

        if (inv.status === 'posted') {
            // Route through the full cancel flow (restores stock, party balance, ledger)
            await executeCancelInvoice(id, { skipNav: true });
        } else {
            // Allow delete only for draft/cancelled
            await DB.delete('invoices', id);
            showToast('Invoice deleted!', 'warning');
        }

        await renderInvoices();

    } catch (err) {
        alert('Error: ' + err.message);
    }
}

// --- Print Invoice ---
function numberToWords(num) {
    const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
    const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
    function convert(n) {
        if (n < 20) return a[n];
        if (n < 100) return b[Math.floor(n / 10)] + (n % 10 !== 0 ? ' ' + a[n % 10] : '');
        if (n < 1000) return a[Math.floor(n / 100)] + 'Hundred ' + (n % 100 !== 0 ? 'and ' + convert(n % 100) : '');
        if (n < 100000) return convert(Math.floor(n / 1000)) + 'Thousand ' + (n % 1000 !== 0 ? convert(n % 1000) : '');
        if (n < 10000000) return convert(Math.floor(n / 100000)) + 'Lakh ' + (n % 100000 !== 0 ? convert(n % 100000) : '');
        return convert(Math.floor(n / 10000000)) + 'Crore ' + (n % 10000000 !== 0 ? convert(n % 10000000) : '');
    }
    const dec = Math.round((num % 1) * 100);
    const intPart = Math.floor(num);
    if (intPart === 0 && dec === 0) return 'Zero';
    let res = intPart > 0 ? 'Rupees ' + convert(intPart) : '';
    if (dec > 0) res += (res ? 'and ' : '') + convert(dec) + 'Paise ';
    return res.trim() + ' Only';
}

function _buildInvoicePageHtml(inv, party, order, co, qrUrl, copyLabel) {
    const items = typeof inv.items === 'string' ? JSON.parse(inv.items) : (inv.items || []);
    const coStateCode = (co.gstin || '').substring(0, 2);
    const paStateCode = (party.gstin || '').substring(0, 2);
    const isSameState = coStateCode === paStateCode && coStateCode.length === 2;

    // Tax: use per-item baseAmount if available, else back-calculate from total
    const totalTaxable = items.reduce((s, it) => s + (it.baseAmount != null ? +it.baseAmount : 0), 0);
    const totalTax = items.reduce((s, it) => s + (it.taxAmount != null ? +it.taxAmount : 0), 0);
    const subTotal = inv.subtotal || items.reduce((s, it) => s + (it.amount || 0), 0);
    const usedTaxable = totalTaxable > 0 ? totalTaxable : +(subTotal / 1.05).toFixed(2);
    const usedTax = totalTax > 0 ? totalTax : +(subTotal - usedTaxable).toFixed(2);
    const cgst = isSameState ? +(usedTax / 2).toFixed(2) : 0;
    const sgst = isSameState ? +(usedTax / 2).toFixed(2) : 0;
    const igst = !isSameState ? usedTax : 0;

    const displayInvNo = inv.vyaparInvoiceNo || inv.invoiceNo;
    const invDate = inv.date ? new Date(inv.date) : new Date();
    const timeStr = inv.createdAt ? new Date(inv.createdAt).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true }) : '';

    return `
<div class="page">
  <div class="copy-label">${copyLabel}</div>
  <div style="text-align:center;margin-bottom:4px"><strong style="font-size:1.1rem;letter-spacing:1px">Tax Invoice</strong></div>
  <div class="inv-header">
    <div class="inv-logo">
      ${co.logo ? `<img src="${co.logo}" style="max-height:80px;max-width:150px;object-fit:contain">` : ''}
    </div>
    <div class="inv-co">
      <div class="co-name">${escapeHtml(co.name || 'Company Name')}</div>
      <div>${escapeHtml(co.address || '')}</div>
      <div>Phone no.: ${escapeHtml(co.phone || '')}${co.email ? ` Email: ${escapeHtml(co.email)}` : ''}</div>
      <div>GSTIN: ${escapeHtml(co.gstin || 'N/A')}, State: ${coStateCode}-${escapeHtml(co.state || '')}</div>
    </div>
  </div>

  <div class="meta-grid">
    <div class="meta-cell" style="border-right:1px solid #555">
      <div class="meta-head">Bill To</div>
      <div class="party-name">${escapeHtml(inv.partyName)}</div>
      ${party.address ? `<div>${escapeHtml(party.address)}</div>` : ''}
      ${party.city ? `<div>${escapeHtml(party.city)}</div>` : ''}
      <div>Contact No. : ${escapeHtml(party.phone || '')}</div>
    </div>
    <div class="meta-cell" style="border-right:1px solid #555">
      <div class="meta-head">Transportation Details</div>
      <div class="meta-row"><span>Invoice Created By :</span><span style="font-weight:600">${escapeHtml(inv.createdBy||'-')}</span></div>
      ${inv.deliveryDate ? `<div class="meta-row"><span>Delivery Date :</span><span style="font-weight:600">${fmtDate(inv.deliveryDate)}</span></div>` : '<div class="meta-row"><span>Delivery Date :</span><span>-</span></div>'}
      ${inv.boxNo ? `<div class="meta-row"><span>Box/Crate No. :</span><span style="font-weight:600">${escapeHtml(inv.boxNo)}</span></div>` : '<div class="meta-row"><span>Box/Crate No. :</span><span>-</span></div>'}
      <div class="meta-row"><span>Delivered By :</span><span>_____________</span></div>
    </div>
    <div class="meta-cell">
      <div class="meta-head" style="text-align:right">Invoice Details</div>
      <div class="meta-row"><span>Invoice No. :</span><strong>${escapeHtml(displayInvNo)}</strong></div>
      <div class="meta-row"><span>Date :</span><span>${fmtDate(inv.date)}</span></div>
      ${timeStr ? `<div class="meta-row"><span>Time :</span><span>${timeStr}</span></div>` : ''}
      ${inv.dueDate ? `<div class="meta-row"><span>Due Date :</span><span>${fmtDate(inv.dueDate)}</span></div>` : ''}
      ${order.date ? `<div class="meta-row"><span>PO Date :</span><span>${fmtDate(order.date)}</span></div>` : ''}
      ${inv.fromOrder ? `<div class="meta-row"><span>PO Number :</span><span>${escapeHtml(inv.fromOrder)}</span></div>` : ''}
    </div>
  </div>

  <table class="items-tbl">
    <thead>
      <tr>
        <th style="width:28px">#</th>
        <th>Item Name</th>
        <th style="width:60px">HSN/SAC</th>
        <th class="tr" style="width:55px">MRP</th>
        <th class="tr" style="width:40px">QTY</th>
        <th style="width:45px">Unit</th>
        <th class="tr" style="width:75px">Amount</th>
      </tr>
    </thead>
    <tbody>
      ${items.map((it, idx) => `
      <tr>
        <td style="text-align:center">${idx + 1}</td>
        <td style="font-weight:600">${escapeHtml(it.name)}</td>
        <td style="font-size:8pt">${escapeHtml(it.hsn || '')}</td>
        <td class="tr">&#8377; ${(+(it.mrp || it.price || 0)).toFixed(2)}</td>
        <td class="tr">${it.qty}</td>
        <td>${escapeHtml(it.unit || 'Pcs')}</td>
        <td class="tr" style="font-weight:600">&#8377; ${(+(it.amount || 0)).toFixed(2)}</td>
      </tr>`).join('')}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="4" style="font-weight:700;border-top:1.5px solid #333">Total</td>
        <td class="tr" style="font-weight:700;border-top:1.5px solid #333">${items.reduce((s,it)=>s+(+it.qty||0),0)}</td>
        <td style="border-top:1.5px solid #333"></td>
        <td class="tr" style="font-weight:800;border-top:1.5px solid #333">&#8377; ${(subTotal).toFixed(2)}</td>
      </tr>
    </tfoot>
  </table>

  <div class="bottom-grid">
    <div class="tax-section">
      <table class="tax-tbl">
        <thead>
          <tr><th>Tax type</th><th class="tr">Taxable amount</th><th class="tr">Rate</th><th class="tr">Tax amount</th></tr>
        </thead>
        <tbody>
          ${isSameState ? `
          <tr><td>SGST</td><td class="tr">&#8377; ${usedTaxable.toFixed(2)}</td><td class="tr">2.5%</td><td class="tr">&#8377; ${sgst.toFixed(2)}</td></tr>
          <tr><td>CGST</td><td class="tr">&#8377; ${usedTaxable.toFixed(2)}</td><td class="tr">2.5%</td><td class="tr">&#8377; ${cgst.toFixed(2)}</td></tr>
          ` : `
          <tr><td>IGST</td><td class="tr">&#8377; ${usedTaxable.toFixed(2)}</td><td class="tr">5%</td><td class="tr">&#8377; ${igst.toFixed(2)}</td></tr>
          `}
        </tbody>
      </table>
      <div class="words-box">
        <div class="section-label">Invoice Amount In Words</div>
        <div style="text-transform:capitalize;font-size:0.82rem">${numberToWords(inv.total)}</div>
      </div>
      <div class="pay-box">
        <div class="section-label">Payment mode</div>
        <div style="text-align:center;font-size:0.88rem">${escapeHtml(inv.paymentMode || 'Cash')}</div>
      </div>
      <div class="bank-box">
        <div class="section-label">Bank Details</div>
        ${qrUrl ? `<div style="margin-top:4px"><img src="${qrUrl}" style="width:80px;height:80px"><br><span style="font-size:0.6rem;color:#555">UPI SCAN TO PAY</span></div>` : ''}
      </div>
    </div>
    <div class="amt-section">
      <div class="amt-row"><span>Sub Total</span><span>&#8377; ${subTotal.toFixed(2)}</span></div>
      <div class="amt-row"><span>Round off</span><span>${(inv.roundOff||0) >= 0 ? '' : ''} &#8377; ${Math.abs(+(inv.roundOff||0)).toFixed(2)}${(inv.roundOff||0) < 0 ? ' (-)' : ''}</span></div>
      <div class="amt-row grand"><span>Total</span><span>&#8377; ${(inv.total||0).toFixed(2)}</span></div>
      <div class="amt-row" style="background:#fffbeb;color:#92400e"><span>Current Balance</span><span>&#8377; ${(party.balance||0).toFixed(2)}</span></div>
      <div style="flex:1"></div>
      <div style="text-align:right;padding:10px 8px;font-size:0.8rem">For : <strong>${escapeHtml(co.name||'')}</strong></div>
      <div class="sign-area">
        ${co.signature ? `<div style="text-align:center;margin-bottom:4px"><img src="${co.signature}" style="max-height:50px;max-width:120px;object-fit:contain"></div>` : '<div style="height:44px"></div>'}
        <div style="border-top:1px solid #333;padding-top:5px;text-align:center;font-weight:700;font-size:0.8rem">Authorized Signatory</div>
      </div>
    </div>
  </div>
</div>`;
}

async function printInvoice(id) {
    const [invoices, co, parties, orders] = await Promise.all([
        DB.getAll('invoices'),
        DB.getObj('db_company'),
        DB.getAll('parties'),
        DB.getAll('sales_orders')
    ]);
    const inv = invoices.find(x => x.id === id);
    if (!inv) return alert('Invoice not found');

    const upiLink = co.upi ? `upi://pay?pa=${co.upi}&pn=${encodeURIComponent(co.name)}&am=${inv.total}&cu=INR` : '';
    let qrUrl = '';
    if (upiLink && typeof QRCode !== 'undefined') {
        const div = document.createElement('div');
        new QRCode(div, { text: upiLink, width: 80, height: 80, correctLevel: QRCode.CorrectLevel.M });
        const obj = div.querySelector('canvas') || div.querySelector('img');
        if (obj) qrUrl = obj.toDataURL ? obj.toDataURL() : obj.src;
    }

    const party = parties.find(p => p.id === inv.partyId) || {};
    const order = orders.find(o => o.orderNo === inv.fromOrder) || {};
    const bodyHtml = _buildInvoicePageHtml(inv, party, order, co, qrUrl, 'ORIGINAL FOR RECIPIENT')
        + '<div class="copy-divider">- - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -</div>'
        + _buildInvoicePageHtml(inv, party, order, co, qrUrl, 'DUPLICATE FOR COLLECTION');

    _openInvoicePrintWindow(bodyHtml, inv.vyaparInvoiceNo || inv.invoiceNo);
}

