async function _buildInvoicePdfBlob(inv, party, order, co, qrUrl) {
    if (typeof html2pdf === 'undefined') throw new Error('PDF library not loaded — refresh and retry');
    const pageHtml = _buildInvoicePageHtml(inv, party, order, co, qrUrl, 'ORIGINAL FOR RECIPIENT');
    // Use fixed+opacity:0 so html2canvas can measure/render the element properly
    const container = document.createElement('div');
    container.style.cssText = 'position:fixed;top:0;left:0;width:148mm;opacity:0;pointer-events:none;z-index:-9999;background:#fff;overflow:hidden;';
    container.innerHTML = `<style>${_getInvoicePdfCss()}</style>${pageHtml}`;
    document.body.appendChild(container);
    // Allow browser to render layout before capturing
    await new Promise(r => requestAnimationFrame(() => requestAnimationFrame(r)));
    try {
        const blob = await html2pdf().set({
            margin: 0,
            image: { type: 'jpeg', quality: 0.98 },
            html2canvas: { scale: 2, useCORS: true, allowTaint: true, logging: false, backgroundColor: '#ffffff' },
            jsPDF: { unit: 'mm', format: 'a5', orientation: 'portrait' }
        }).from(container.querySelector('.page')).outputPdf('blob');
        if (!blob || blob.size < 500) throw new Error('PDF output is empty — html2canvas may have failed');
        return blob;
    } finally {
        document.body.removeChild(container);
    }
}

async function shareInvoice(id) {
    if (typeof html2pdf === 'undefined') {
        showToast('PDF library not loaded — refresh the page and retry', 'warning');
        return;
    }
    const [invs, parties, co, orders] = await Promise.all([
        DB.getAll('invoices'), DB.getAll('parties'), DB.getObj('db_company'), DB.getAll('sales_orders')
    ]);
    const inv = invs.find(i => i.id === id);
    if (!inv) return alert('Invoice not found');
    const party = parties.find(p => p.id === inv.partyId) || {};
    const order = orders.find(o => o.orderNo === inv.fromOrder) || {};
    const invNo = inv.vyaparInvoiceNo || inv.invoiceNo;
    const upiLink = co.upi ? `upi://pay?pa=${co.upi}&pn=${encodeURIComponent(co.name)}&am=${inv.total}&cu=INR` : '';
    let qrUrl = '';
    if (upiLink && typeof QRCode !== 'undefined') {
        const div = document.createElement('div');
        new QRCode(div, { text: upiLink, width: 80, height: 80, correctLevel: QRCode.CorrectLevel.M });
        const obj = div.querySelector('canvas') || div.querySelector('img');
        if (obj) qrUrl = obj.toDataURL ? obj.toDataURL() : obj.src;
    }
    showToast('Generating PDF...', 'info');
    try {
        const blob = await _buildInvoicePdfBlob(inv, party, order, co, qrUrl);
        const fileName = `Invoice-${invNo}.pdf`;
        const file = new File([blob], fileName, { type: 'application/pdf' });
        const shareTitle = `Invoice ${invNo}`;
        const shareText = `Invoice ${invNo} | ${inv.partyName || ''} | ₹${(inv.total || 0).toFixed(2)}`;
        if (navigator.share) {
            if (navigator.canShare && navigator.canShare({ files: [file] })) {
                // Share with file attachment — include title and text for better platform support
                await navigator.share({ files: [file], title: shareTitle, text: shareText });
            } else {
                // Platform doesn't support file sharing — download PDF and open WhatsApp with text
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = fileName; a.click();
                setTimeout(() => URL.revokeObjectURL(url), 5000);
                showToast('PDF downloaded. Opening WhatsApp to share invoice details...', 'info');
                const waPhone = party.phone ? party.phone.replace(/\D/g, '') : '';
                const waUrl = `https://wa.me/${waPhone}?text=${encodeURIComponent(shareText)}`;
                setTimeout(() => window.open(waUrl, '_blank'), 800);
            }
        } else {
            // navigator.share not supported — download the PDF directly
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; a.download = fileName; a.click();
            setTimeout(() => URL.revokeObjectURL(url), 5000);
            showToast('PDF downloaded — share from your files app', 'info');
        }
    } catch (err) {
        if (err.name === 'AbortError') return; // User dismissed share dialog — not an error
        console.error('shareInvoice error:', err);
        alert('Could not generate PDF: ' + err.message);
    }
}
async function printInvoiceByNo(invoiceNo) {
    const invs = await DB.getAll('invoices');
    const inv = invs.find(i => i.invoiceNo === invoiceNo);
    if (inv) printInvoice(inv.id); else alert('Invoice not found: ' + invoiceNo);
}
async function shareInvoiceByNo(invoiceNo) {
    const invs = await DB.getAll('invoices');
    const inv = invs.find(i => i.invoiceNo === invoiceNo);
    if (inv) shareInvoice(inv.id);
}
async function bulkPrintInvoices() {
    const checked = [...document.querySelectorAll('.inv-chk:checked')].map(c => c.value);
    if (!checked.length) return alert('Select at least one invoice to print.');

    const [invoices, co, parties, orders] = await Promise.all([
        DB.getAll('invoices'),
        DB.getObj('db_company'),
        DB.getAll('parties'),
        DB.getAll('sales_orders')
    ]);

    const upiLink = co.upi ? `upi://pay?pa=${co.upi}&pn=${encodeURIComponent(co.name)}&cu=INR` : '';
    let qrUrl = '';
    if (upiLink && typeof QRCode !== 'undefined') {
        const div = document.createElement('div');
        new QRCode(div, { text: upiLink + '&am=0', width: 80, height: 80, correctLevel: QRCode.CorrectLevel.M });
        const obj = div.querySelector('canvas') || div.querySelector('img');
        if (obj) qrUrl = obj.toDataURL ? obj.toDataURL() : obj.src;
    }

    let bodyHtml = '';
    checked.forEach((id, idx) => {
        const inv = invoices.find(x => x.id === id);
        if (!inv) return;
        const party = parties.find(p => p.id === inv.partyId) || {};
        const order = orders.find(o => o.orderNo === inv.fromOrder) || {};
        if (idx > 0) bodyHtml += '<div class="page-break"></div>';
        bodyHtml += _buildInvoicePageHtml(inv, party, order, co, qrUrl, 'ORIGINAL FOR RECIPIENT')
            + '<div class="copy-divider">- - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -</div>'
            + _buildInvoicePageHtml(inv, party, order, co, qrUrl, 'DUPLICATE FOR COLLECTION');
    });

    _openInvoicePrintWindow(bodyHtml, `Bulk (${checked.length} invoices)`);
}

function _getInvoicePrintCss() {
    return `
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');
  * { box-sizing: border-box; }
  body { font-family: 'Inter', sans-serif; color: #1a1a1a; margin: 0; padding: 10px; font-size: 8.5pt; line-height: 1.3; background: #fff; }
  .page { width: 148mm; padding: 5mm 7mm; margin: 0 auto 6px; background: #fff; border: 1px solid #ccc; position: relative; }
  .page-break { page-break-after: always; break-after: page; height: 0; }
  .copy-label { position: absolute; top: 8mm; right: 10mm; font-size: 0.68rem; font-weight: 700; color: #555; text-align: right; }
  .inv-header { display: flex; gap: 10px; align-items: flex-start; border: 1px solid #444; border-bottom: none; padding: 8px 10px; }
  .inv-logo { min-width: 100px; }
  .inv-co { flex: 1; text-align: right; font-size: 0.8rem; }
  .co-name { font-size: 1rem; font-weight: 800; }
  .meta-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; border: 1px solid #444; margin-bottom: 0; }
  .meta-cell { padding: 7px 9px; font-size: 0.78rem; }
  .meta-head { font-weight: 800; background: #444; color: #fff; margin: -7px -9px 6px; padding: 4px 9px; font-size: 0.75rem; }
  .meta-row { display: flex; justify-content: space-between; gap: 6px; padding: 1px 0; }
  .party-name { font-weight: 800; font-size: 0.92rem; overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:100%; }
  .items-tbl { width: 100%; border-collapse: collapse; border: 1px solid #444; margin-top: 0; }
  .items-tbl th { background: #444; color: #fff; padding: 6px 5px; font-size: 0.72rem; text-align: left; border: 1px solid #555; }
  .items-tbl td { padding: 5px 5px; border: 1px solid #aaa; font-size: 8.5pt; word-break:break-word; }
  .items-tbl tfoot td { background: #f5f5f5; font-size: 8.5pt; }
  .tr { text-align: right; }
  .bottom-grid { display: grid; grid-template-columns: 55% 45%; border: 1px solid #444; border-top: none; }
  .tax-section { border-right: 1px solid #444; display: flex; flex-direction: column; }
  .tax-tbl { width: 100%; border-collapse: collapse; }
  .tax-tbl th { background: #444; color: #fff; padding: 5px 6px; font-size: 0.7rem; border: 1px solid #555; }
  .tax-tbl td { padding: 4px 6px; border: 1px solid #ccc; font-size: 8.5pt; }
  .words-box { border-top: 1px solid #aaa; padding: 6px 8px; }
  .pay-box { border-top: 1px solid #aaa; padding: 6px 8px; }
  .bank-box { border-top: 1px solid #aaa; padding: 6px 8px; flex: 1; }
  .section-label { font-weight: 800; font-size: 0.72rem; background: #444; color: #fff; margin: -6px -8px 5px; padding: 3px 8px; }
  .amt-section { display: flex; flex-direction: column; }
  .amt-row { display: flex; justify-content: space-between; padding: 5px 10px; border-bottom: 0.5px solid #ccc; font-size: 0.82rem; }
  .amt-row.grand { background: #444; color: #fff; font-weight: 800; font-size: 0.95rem; }
  .sign-area { padding: 6px 10px 8px; text-align: right; }
  .copy-divider { text-align: center; font-size: 7.5pt; color: #bbb; letter-spacing: 1px; padding: 2px 0; margin: 0; line-height: 1; }
  @media print {
    @page { size: A5 portrait; margin: 8mm; }
    body { padding: 0; margin: 0; }
    .page { border: none; padding: 3mm 6mm; width: 100%; margin: 0; max-height: 100mm; overflow: hidden; }
    .copy-divider { color: #999; page-break-after: avoid; break-after: avoid; }
    .page-break { page-break-after: always; break-after: page; height: 0; }
    #inv-print-close-btn { display: none !important; }
  }`;
}

function _openInvoicePrintWindow(bodyHtml, title) {
    // Build full-screen overlay with Vyapar-style action bar
    let overlay = document.getElementById('inv-print-overlay');
    if (overlay) overlay.remove();
    overlay = document.createElement('div');
    overlay.id = 'inv-print-overlay';
    document.body.appendChild(overlay);

    const css = _getInvoicePrintCss();
    overlay.innerHTML = `
        <style>
            #inv-print-overlay {
                position:fixed;inset:0;z-index:99999;background:#f1f3f5;
                display:flex;flex-direction:column;overflow:hidden;
            }
            #inv-print-topbar {
                display:flex;align-items:center;gap:10px;
                background:#1e293b;color:#fff;padding:10px 16px;
                font-size:0.95rem;font-weight:600;flex-shrink:0;
            }
            #inv-print-topbar button {
                background:none;border:none;color:#fff;font-size:1.3rem;
                cursor:pointer;padding:4px 8px;border-radius:6px;line-height:1;
            }
            #inv-print-topbar button:hover { background:rgba(255,255,255,0.15); }
            #inv-print-doc-area {
                flex:1;overflow-y:auto;padding:16px;
                display:flex;justify-content:center;
            }
            #inv-print-doc-area .doc-wrap {
                background:#fff;box-shadow:0 4px 24px rgba(0,0,0,0.18);
                border-radius:4px;width:100%;max-width:600px;
            }
            #inv-print-action-bar {
                background:#fff;border-top:1px solid #e2e8f0;
                padding:12px 16px;display:flex;gap:10px;
                justify-content:center;flex-shrink:0;
                box-shadow:0 -2px 12px rgba(0,0,0,0.08);
            }
            #inv-print-action-bar button {
                flex:1;max-width:160px;padding:11px 8px;
                border-radius:10px;font-size:0.88rem;font-weight:600;
                border:none;cursor:pointer;display:flex;flex-direction:column;
                align-items:center;gap:4px;transition:opacity 0.2s;
            }
            #inv-print-action-bar button:active { opacity:0.75; }
            #inv-print-action-bar button .ab-icon { font-size:1.4rem; }
            .ab-share  { background:#6366f1;color:#fff; }
            .ab-download { background:#0ea5e9;color:#fff; }
            .ab-print  { background:#f97316;color:#fff; }
            @media print {
                #inv-print-topbar, #inv-print-action-bar { display:none !important; }
                #inv-print-overlay { background:#fff; display:block !important; overflow:visible !important; }
                #inv-print-doc-area { overflow:visible;padding:0; }
                ${css}
            }
        </style>
        <style>${css}</style>
        <div id="inv-print-topbar">
            <button onclick="document.getElementById('inv-print-overlay').remove()" title="Close">✕</button>
            <span style="flex:1">${escapeHtml(title)}</span>
        </div>
        <div id="inv-print-doc-area">
            <div class="doc-wrap">${bodyHtml}</div>
        </div>
        <div id="inv-print-action-bar">
            <button class="ab-share" onclick="_invPdfShare('${escapeHtml(title)}')">
                <span class="ab-icon material-symbols-outlined">share</span>Share
            </button>
            <button class="ab-download" onclick="window.print()">
                <span class="ab-icon material-symbols-outlined">save</span>Save PDF
            </button>
            <button class="ab-print" onclick="window.print()">
                <span class="ab-icon material-symbols-outlined">print</span>Print
            </button>
        </div>`;

    // Close on afterprint (user printed or saved)
    window.addEventListener('afterprint', () => {
        const el = document.getElementById('inv-print-overlay');
        if (el) el.remove();
    }, { once: true });
}

async function _invPdfShare(title) {
    const el = document.querySelector('#inv-print-doc-area .doc-wrap');
    if (!el) return;
    // Use Web Share API if supported
    if (navigator.share) {
        try {
            // Share as text fallback
            await navigator.share({ title: title, text: 'Invoice: ' + title, url: window.location.href });
            return;
        } catch (e) { /* user cancelled or not supported */ }
    }
    // Fallback: trigger print-to-PDF
    window.print();
}




// =============================================
//  PAYMENTS
// =============================================
async function renderPayments() {
    // Restore bottom nav hidden by openPaymentModal
    document.body.classList.remove('pay-form-open');
    const payments = await DB.getAll('payments');
    const isSalesman = currentUser.role === 'Salesman';
    // Salesman sees only their own payments
    const visiblePayments = isSalesman
        ? payments.filter(p => p.collectedBy === currentUser.name || p.createdBy === currentUser.name)
        : payments;
    const totalIn = visiblePayments.filter(p => p.type === 'in').reduce((s, p) => s + p.amount, 0);
    const totalOut = visiblePayments.filter(p => p.type === 'out').reduce((s, p) => s + p.amount, 0);

    // Mode-wise breakup for Payment In
    const modeBreakup = {};
    visiblePayments.filter(p => p.type === 'in').forEach(p => {
        const m = p.mode || 'Cash';
        modeBreakup[m] = (modeBreakup[m] || 0) + p.amount;
    });
    const modeChips = Object.entries(modeBreakup).map(([m, a]) =>
        `<div class="pay-mode-chip"><span>${m}</span><strong>${currency(a)}</strong></div>`).join('');

    const today1 = today();
    const monthStart = today1; // User requested today as default

    const isMobile = window.innerWidth < 768;
    const collectorOptions = !isSalesman ? `<option value="">All</option>${[...new Set(visiblePayments.map(p => p.collectedBy || p.createdBy).filter(Boolean))].map(n => `<option>${escapeHtml(n)}</option>`).join('')}` : '';

    if (isMobile) {
        pageContent.innerHTML = `
        <!-- Mobile: compact stat + mode strip -->
        <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:12px;padding:10px 12px;margin-bottom:10px">
            <div style="display:flex;gap:0;margin-bottom:${modeChips ? '8px' : '0'}">
                <div style="flex:1;text-align:center;border-right:1px solid var(--border);padding-right:8px">
                    <div style="font-size:0.65rem;color:var(--text-muted);font-weight:700;text-transform:uppercase">↗ Pay In</div>
                    <div id="pay-stat-in" style="font-size:1.2rem;font-weight:800;color:var(--success)">${currency(totalIn)}</div>
                </div>
                ${!isSalesman ? `<div style="flex:1;text-align:center;padding-left:8px">
                    <div style="font-size:0.65rem;color:var(--text-muted);font-weight:700;text-transform:uppercase">↙ Pay Out</div>
                    <div id="pay-stat-out" style="font-size:1.2rem;font-weight:800;color:var(--danger)">${currency(totalOut)}</div>
                </div>` : `<div id="pay-stat-out" style="display:none"></div>`}
            </div>
            ${modeChips ? `<div id="pay-mode-bar-wrap" style="display:flex;gap:6px;overflow-x:auto;padding:4px 0;scrollbar-width:none">
                <span style="font-size:0.65rem;font-weight:700;color:var(--text-muted);white-space:nowrap;align-self:center">MODE:</span>
                <div id="pay-mode-chips" style="display:flex;gap:6px;overflow-x:auto;scrollbar-width:none">${modeChips}</div>
            </div>` : `<div id="pay-mode-bar-wrap" style="display:none"><div id="pay-mode-chips"></div></div>`}
        </div>

        <!-- Mobile: compact filter strip -->
        <div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:10px;margin-bottom:10px">
            <div style="display:flex;gap:6px;align-items:center;margin-bottom:6px">
                <input type="date" id="pay-f-from" value="${monthStart}" onchange="filterPayTable()" style="flex:1;font-size:0.78rem;padding:7px 8px;border:1px solid var(--border);border-radius:7px;background:var(--bg-input)">
                <span style="color:var(--text-muted);font-size:0.8rem">–</span>
                <input type="date" id="pay-f-to" value="${today1}" onchange="filterPayTable()" style="flex:1;font-size:0.78rem;padding:7px 8px;border:1px solid var(--border);border-radius:7px;background:var(--bg-input)">
                <button onclick="togglePayFilters()" id="pay-filter-toggle" style="border:1px solid var(--border);background:var(--bg-input);border-radius:7px;padding:7px 10px;font-size:0.85rem;cursor:pointer;flex-shrink:0"><span class="material-symbols-outlined" style="font-size:1rem;vertical-align:-3px">tune</span></button>
                <button class="btn btn-primary btn-sm" onclick="openPaymentModal()" style="white-space:nowrap;padding:7px 14px;flex-shrink:0">+ Record</button>
            </div>
            <div id="pay-extra-filters" style="display:none">
                <input id="pay-search" placeholder="Search parties/receipts..." oninput="filterPayTable()" style="width:100%;margin-bottom:6px;padding:7px 10px;border:1px solid var(--border);border-radius:7px;font-size:0.82rem;background:var(--bg-input);box-sizing:border-box">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
                    <select id="pay-type-filter" onchange="filterPayTable()" style="padding:7px;border:1px solid var(--border);border-radius:7px;font-size:0.78rem;background:var(--bg-input)"><option value="">All Types</option><option value="in">Payment In</option><option value="out">Payment Out</option></select>
                    <select id="pay-mode-filter" onchange="filterPayTable()" style="padding:7px;border:1px solid var(--border);border-radius:7px;font-size:0.78rem;background:var(--bg-input)"><option value="">All Modes</option><option>Cash</option><option>UPI</option><option>Cheque</option><option>Bank Transfer</option></select>
                    ${!isSalesman ? `<select id="pay-collector-filter" onchange="filterPayTable()" style="padding:7px;border:1px solid var(--border);border-radius:7px;font-size:0.78rem;background:var(--bg-input);grid-column:span 2">${collectorOptions}</select>` : ''}
                </div>
            </div>
        </div>

        <!-- Mobile: payment entry cards -->
        <div id="pay-list">${renderPayCards(visiblePayments)}</div>
        <div id="pay-tbody" style="display:none"></div>
        <table id="tbl-payments" style="display:none"><tbody></tbody></table>`;
    } else {
        pageContent.innerHTML = `
        <div class="stats-grid" style="margin-bottom:14px" id="pay-stat-tiles">
            <div class="stat-card green"><div class="stat-icon"></div><div class="stat-value" id="pay-stat-in">${currency(totalIn)}</div><div class="stat-label">Payment In</div></div>
            ${!isSalesman ? `<div class="stat-card red"><div class="stat-icon"></div><div class="stat-value" id="pay-stat-out">${currency(totalOut)}</div><div class="stat-label">Payment Out</div></div>` : ''}
        </div>
        <div id="pay-mode-bar-wrap">
            <div class="pay-summary-bar">
                <div class="pay-summary-total">
                    <span class="pay-sum-label">Mode Breakup (In)</span>
                    <span class="pay-sum-value" id="pay-mode-total">${currency(totalIn)}</span>
                </div>
                <div class="pay-summary-modes" id="pay-mode-chips">${modeChips}</div>
            </div>
        </div>
        <div class="pay-toolbar-compact">
            <div class="pay-filters-section">
                <div class="pay-filter-group"><label>From</label><input type="date" id="pay-f-from" value="${monthStart}" onchange="filterPayTable()"></div>
                <div class="pay-filter-group"><label>To</label><input type="date" id="pay-f-to" value="${today1}" onchange="filterPayTable()"></div>
                <div class="pay-filter-group" style="flex:1.5;min-width:180px"><label>Search</label><input id="pay-search" placeholder="Search parties/receipts..." oninput="filterPayTable()" class="search-box" style="margin:0"></div>
                <div class="pay-filter-group"><label>Type</label><select id="pay-type-filter" onchange="filterPayTable()"><option value="">All Types</option><option value="in">Payment In</option><option value="out">Payment Out</option></select></div>
                <div class="pay-filter-group"><label>Mode</label><select id="pay-mode-filter" onchange="filterPayTable()"><option value="">All Modes</option><option>Cash</option><option>UPI</option><option>Cheque</option><option>Bank Transfer</option></select></div>
                ${!isSalesman ? `<div class="pay-filter-group"><label>Collector</label><select id="pay-collector-filter" onchange="filterPayTable()">${collectorOptions}</select></div>` : ''}
                <div style="display:flex;gap:6px;align-items:center;padding-top:14px">
                    <button class="btn btn-outline btn-sm" onclick="DB.exportToExcel('tbl-payments', 'payments')" title="Export Excel" style="border-color:#16a34a;color:#16a34a"><span class="material-symbols-outlined" style="font-size:1.1rem">download</span></button>
                    <button class="btn btn-outline btn-sm" onclick="openColumnPersonalizer('payments','renderPayments')" title="Column Config" style="border-color:var(--accent);color:var(--accent)"><span class="material-symbols-outlined" style="font-size:1.1rem">view_column</span></button>
                    <button class="btn btn-primary" onclick="openPaymentModal()" style="white-space:nowrap;padding:8px 16px">+ Record</button>
                </div>
            </div>
        </div>
        <div class="card" style="margin-top:12px"><div class="card-body">
            <div class="table-wrapper">
                <table class="data-table" id="tbl-payments"><thead><tr>${ColumnManager.get('payments').filter(c => c.visible).map(c => `<th>${c.label}</th>`).join('')}</tr></thead>
                <tbody id="pay-tbody">${renderPayRows(visiblePayments)}</tbody></table>
            </div>
        </div></div>
        <div id="pay-list" style="display:none"></div>`;
    }
    filterPayTable();
}
function togglePayFilters() {
    const extra = $('pay-extra-filters');
    const btn = $('pay-filter-toggle');
    if (!extra) return;
    const open = extra.style.display !== 'none';
    extra.style.display = open ? 'none' : 'block';
    if (btn) btn.style.background = open ? 'var(--bg-input)' : 'var(--primary)';
    if (btn) btn.style.color = open ? '' : '#fff';
}

function renderPayCards(pays) {
    if (!pays.length) return `<div style="text-align:center;padding:40px 20px;color:var(--text-muted)"><div style="margin-bottom:8px"></div><div>No payments found</div></div>`;
    return pays.map(p => {
        const isIn = p.type === 'in';
        const amtColor = isIn ? 'var(--success)' : 'var(--danger)';
        const amtSign = isIn ? '+' : '−';
        const typeLabel = isIn ? 'IN' : 'OUT';
        const typeBg = isIn ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)';
        const typeColor = isIn ? 'var(--success)' : 'var(--danger)';
        const invCell = p.allocations && Object.keys(p.allocations).length > 0
            ? Object.keys(p.allocations).join(', ')
            : (p.invoiceNo || '');
        return `<div style="background:var(--bg-card);border:1px solid var(--border);border-radius:10px;padding:12px 14px;margin-bottom:8px;display:flex;align-items:center;gap:12px" onclick="viewPaymentDetails('${p.id}')">
            <div style="flex:1;min-width:0">
                <div style="display:flex;align-items:center;gap:6px;margin-bottom:3px">
                    <span style="font-weight:700;font-size:0.9rem;color:var(--accent)">${escapeHtml(p.payNo || '')}</span>
                    <span style="font-size:0.68rem;font-weight:700;background:${typeBg};color:${typeColor};padding:2px 7px;border-radius:20px">${typeLabel}</span>
                    ${p.mode && p.mode !== 'Cash' ? `<span style="font-size:0.68rem;color:var(--text-muted);background:var(--bg-secondary);padding:2px 6px;border-radius:10px">${escapeHtml(p.mode)}</span>` : ''}
                </div>
                <div style="font-weight:600;font-size:0.88rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml(p.partyName || '')}</div>
                <div style="font-size:0.75rem;color:var(--text-muted);margin-top:2px">${fmtDate(p.date)}${invCell ? ' · ' + escapeHtml(invCell) : ''}${p.collectedBy ? ' · ' + escapeHtml(p.collectedBy) : ''}</div>
            </div>
            <div style="text-align:right;flex-shrink:0">
                <div style="font-size:1.1rem;font-weight:800;color:${amtColor}">${amtSign}${currency(p.amount)}</div>
                ${p.mode === 'Cash' ? `<div style="font-size:0.65rem;color:var(--text-muted)">CASH</div>` : ''}
            </div>
        </div>`;
    }).join('');
}

function buildPayInvoiceCell(p) {
    if (p.allocations && Object.keys(p.allocations).length > 0) {
        return Object.entries(p.allocations).map(([inv, amt]) => `${inv} - ${AMT(amt)}`).join(', ');
    }
    return p.invoiceNo || '-';
}
function AMT(v) { return (+v).toFixed(0); }

function renderPayRows(pays) {
    if (!pays.length) return '<tr><td colspan="9" class="empty-state"><p>No payments found</p></td></tr>';
    const cols = ColumnManager.get('payments').filter(c => c.visible);
    return pays.map(p => {
        const editBtn = canEdit() ? `<button class="btn-icon" onclick="openEditPaymentModal('${p.id}')" title="Edit"><span class="material-symbols-outlined" style="font-size:1.1rem">edit</span></button>` : '';
        const cellMap = {
            date: `<td>${fmtDate(p.date)}</td>`,
            receiptNo: `<td style="font-weight:600;color:var(--accent)">${p.payNo || (p.id ? p.id.substring(0, 8) : '-')}</td>`,
            party: `<td style="font-weight:600">${escapeHtml(p.partyName)}</td>`,
            type: `<td style="min-width:120px"><span class="badge ${p.type === 'in' ? 'badge-success' : 'badge-danger'}">${p.type === 'in' ? 'Payment In' : 'Payment Out'}</span></td>`,
            invoiceNo: `<td>${buildPayInvoiceCell(p)}</td>`,
            mode: `<td>${p.mode || 'Cash'}${p.mode === 'Cheque' && p.chequeNo ? `<br><span style="font-size:0.75rem;color:var(--text-muted)">#${p.chequeNo} | ${p.chequeBank || ''}</span><br><span class="badge ${p.chequeStatus === 'Cleared' ? 'badge-success' : p.chequeStatus === 'Deposited' ? 'badge-warning' : 'badge-danger'}" style="font-size:0.65rem">${p.chequeStatus || 'Pending'}</span>` : ''}</td>`,
            collectedBy: `<td style="font-size:0.82rem;color:var(--text-secondary)">${escapeHtml(p.collectedBy || p.createdBy || '-')}</td>`,
            amount: `<td class="${p.type === 'in' ? 'amount-green' : 'amount-red'}">${currency(p.amount)}</td>`,
            status: `<td><span class="badge ${p.status === 'posted' ? 'badge-success' : p.status === 'cancelled' ? 'badge-danger' : 'badge-warning'}" style="font-size:0.72rem">${p.status || 'pending'}</span></td>`,
            actions: `<td><div class="action-btns">${editBtn}${canEdit() ? `<button class="btn-icon" onclick="deletePayment('${p.id}')" title="Delete Payment" style="color:var(--danger)"><span class="material-symbols-outlined" style="font-size:1.1rem">delete</span></button>` : ''}</div></td>`,
        };
        return `<tr>${cols.map(c => cellMap[c.key] || '').join('')}</tr>`;
    }).join('');
}
async function filterPayTable() {
    const s = ($('pay-search') || {}).value?.toLowerCase() || '';
    const t = ($('pay-type-filter') || {}).value || '';
    const modeF = ($('pay-mode-filter') || {}).value || '';
    const collF = ($('pay-collector-filter') || {}).value || '';
    const from = ($('pay-f-from') || {}).value || '';
    const to = ($('pay-f-to') || {}).value || '';
    let pays = await DB.getAll('payments');
    if (currentUser && currentUser.role === 'Salesman') {
        pays = pays.filter(p => (p.collectedBy === currentUser.name || p.createdBy === currentUser.name) && p.type !== 'out');
    }
    if (from) pays = pays.filter(p => p.date >= from);
    if (to) pays = pays.filter(p => p.date <= to);
    if (s) pays = pays.filter(p => (p.partyName || '').toLowerCase().includes(s) || (p.note || '').toLowerCase().includes(s) || (p.invoiceNo || '').toLowerCase().includes(s));
    if (t) pays = pays.filter(p => p.type === t);
    if (modeF) pays = pays.filter(p => (p.mode || 'Cash') === modeF);
    if (collF) pays = pays.filter(p => (p.collectedBy || p.createdBy) === collF);
    // Update table or cards depending on view
    const listEl = $('pay-list');
    const tbodyEl = $('pay-tbody');
    if (listEl && listEl.style.display !== 'none') {
        listEl.innerHTML = renderPayCards(pays);
    } else if (tbodyEl) {
        tbodyEl.innerHTML = renderPayRows(pays);
    }

    // Update stat tiles
    const filtIn = pays.filter(p => p.type === 'in').reduce((s, p) => s + p.amount, 0);
    const filtOut = pays.filter(p => p.type === 'out').reduce((s, p) => s + p.amount, 0);
    if ($('pay-stat-in')) $('pay-stat-in').textContent = currency(filtIn);
    if ($('pay-stat-out')) $('pay-stat-out').textContent = currency(filtOut);

    // Update mode breakup (desktop bar or mobile chips)
    const mb = {};
    pays.filter(p => p.type === 'in').forEach(p => { const m = p.mode || 'Cash'; mb[m] = (mb[m] || 0) + p.amount; });
    const chips = Object.entries(mb).map(([m, a]) => `<div class="pay-mode-chip"><span>${m}</span><strong>${currency(a)}</strong></div>`).join('');
    const modeChipsEl = $('pay-mode-chips');
    if (modeChipsEl) modeChipsEl.innerHTML = chips;
    const wrap = $('pay-mode-bar-wrap');
    if (wrap && wrap.querySelector('.pay-summary-bar')) {
        // Desktop: update total value
        const totalEl = wrap.querySelector('#pay-mode-total') || wrap.querySelector('.pay-sum-value');
        if (totalEl) totalEl.textContent = currency(filtIn);
        if (!chips) wrap.style.display = 'none'; else wrap.style.display = '';
    } else if (wrap) {
        // Mobile: show/hide the mode strip
        if (!chips) wrap.style.display = 'none'; else { wrap.style.display = 'flex'; }
    }
}

function viewInvoiceByNo(invoiceNo) {
    const inv = DB.get('db_invoices').find(i => i.invoiceNo === invoiceNo);
    if (inv) viewInvoice(inv.id);
}

async function viewPaymentDetails(id) {
    const payments = await DB.getAll('payments');
    const p = payments.find(x => x.id === id);
    if (!p) return;
    openModal('Payment Receipt', `
        <div style="background:var(--bg-card);padding:20px;border-radius:var(--radius-md);border:1px solid var(--border)">
            <div style="display:flex;justify-content:space-between;margin-bottom:15px;border-bottom:1px solid var(--border);padding-bottom:10px">
                <div>
                    <h3 style="margin:0;font-size:1.1rem">${p.partyName}</h3>
                    <div style="font-size:0.85rem;color:var(--text-muted)">Date: ${fmtDate(p.date)}</div>
                </div>
                <div style="text-align:right">
                    <span class="badge ${p.type === 'in' ? 'badge-success' : 'badge-danger'}">${p.type === 'in' ? 'Payment In' : 'Payment Out'}</span>
                </div>
            </div>
            <table style="width:100%;font-size:0.9rem;border-collapse:collapse;margin-bottom:15px">
                <tr style="border-bottom:1px dashed var(--border)"><td style="padding:8px 0;color:var(--text-secondary)">Payment Mode</td><td style="padding:8px 0;text-align:right;font-weight:600">${p.mode || 'Cash'}</td></tr>
                <tr style="border-bottom:1px dashed var(--border)"><td style="padding:8px 0;color:var(--text-secondary)">Amount</td><td style="padding:8px 0;text-align:right;font-weight:700;font-size:1.1rem;color:${p.type === 'in' ? 'var(--success)' : 'var(--danger)'}">${currency(p.amount)}</td></tr>
                <tr style="border-bottom:1px dashed var(--border)"><td style="padding:8px 0;color:var(--text-secondary);vertical-align:top">Invoice(s)</td><td style="padding:8px 0;text-align:right">
                    ${p.allocations && Object.keys(p.allocations).length > 0
            ? `<table style="width:100%;font-size:0.82rem;border-collapse:collapse">
                            ${Object.entries(p.allocations).map(([inv, amt]) => `
                            <tr>
                                <td style="padding:2px 0"><a href="#" onclick="viewInvoiceByNo('${inv}');return false" style="color:var(--primary);font-weight:600">${escapeHtml(inv)}</a></td>
                                <td style="text-align:right;font-weight:700;color:var(--success)">${(+amt).toFixed(2)}</td>
                            </tr>`).join('')}
                            ${(() => { const used = Object.values(p.allocations).reduce((s, v) => s + (+v), 0); const rem = p.amount - used; return rem > 0.01 ? `<tr><td style="padding:2px 0;color:var(--text-muted)">Unallocated</td><td style="text-align:right;color:var(--accent);font-weight:700">${rem.toFixed(2)}</td></tr>` : ''; })()}
                          </table>`
            : (p.invoiceNo && p.invoiceNo !== 'Advance'
                ? `<a href="#" onclick="viewInvoiceByNo('${p.invoiceNo}');return false" style="color:var(--accent);text-decoration:underline">${escapeHtml(p.invoiceNo)}</a>`
                : `<span style="color:var(--text-muted)">${p.invoiceNo === 'Advance' ? 'Advance' : 'Unlinked'}</span>`)}
                </td></tr>
                <tr><td style="padding:8px 0;color:var(--text-secondary)">Note</td><td style="padding:8px 0;text-align:right">${p.note || '-'}</td></tr>
            </table>
        </div>
        <div class="modal-actions">
            <button class="btn btn-outline" onclick="closeModal()">Close</button>
            ${canEdit() ? `<button class="btn btn-outline" style="color:var(--danger);border-color:var(--danger)" onclick="closeModal();deletePayment('${p.id}')"><span class="material-symbols-outlined" style="font-size:1rem;vertical-align:-2px">delete</span> Delete</button>` : ''}
            ${canEdit() ? `<button class="btn btn-outline" onclick="closeModal();openEditPaymentModal('${p.id}')"><span class="material-symbols-outlined" style="font-size:1rem;vertical-align:-2px">edit</span> Edit</button>` : ''}
            <button class="btn btn-primary" onclick="printPaymentReceipt('${p.id}')"> Print Receipt</button>
        </div>
    `);
}
function _getPaymentPrintCss() {
    return `
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');
  * { box-sizing: border-box; }
  body { font-family: 'Inter', sans-serif; color: #1a1a1a; margin: 0; padding: 10px; font-size: 8.5pt; line-height: 1.4; background: #fff; }
  .page { width: 148mm; padding: 8mm 10mm; margin: 0 auto; background: #fff; border: 1px solid #ccc; position: relative; }
  .voucher-title { text-align: center; font-size: 1.2rem; font-weight: 800; font-style: italic; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 10px; border-bottom: 2px solid #333; padding-bottom: 5px; }
  .inv-header { display: flex; gap: 10px; align-items: flex-start; margin-bottom: 12px; }
  .inv-logo { min-width: 90px; max-width: 120px; }
  .inv-co { flex: 1; text-align: left; font-size: 0.85rem; }
  .co-name { font-size: 1.15rem; font-weight: 800; }
  .meta-grid { display: grid; grid-template-columns: 1fr 1fr; border: 1px solid #444; margin-bottom: 12px; }
  .meta-cell { padding: 8px 10px; font-size: 0.82rem; }
  .meta-cell label { font-size: 0.72rem; color: #555; font-weight: 700; text-transform: uppercase; display: block; margin-bottom: 2px; }
  .party-name { font-weight: 800; font-size: 1.05rem; }
  .details-tbl { width: 100%; border-collapse: collapse; border: 1px solid #444; margin-bottom: 16px; }
  .details-tbl th { background: #444; color: #fff; padding: 7px 8px; font-size: 0.78rem; text-align: left; border: 1px solid #555; }
  .details-tbl td { padding: 8px 8px; border: 1px solid #aaa; font-size: 0.9rem; }
  .btn-print { margin-top:16px;padding:8px 20px;background:#f97316;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:1rem; display: block; margin: 20px auto 0; }
  .sign-area { display: flex; justify-content: space-between; margin-top: 40px; padding: 0 10px; }
  .sign-box { text-align: center; font-weight: 700; font-size: 0.8rem; border-top: 1px solid #333; padding-top: 5px; width: 120px; }
  @media print {
    @page { size: A5 portrait; margin: 0; }
    body { padding: 0; margin: 0; }
    .page { border: none; padding: 6mm 10mm; width: 100%; height: 100vh; margin: 0; max-height: unset; overflow: hidden; }
    .btn-print { display: none !important; }
  }`;
}

function _buildPaymentPageHtml(p, co) {
    const isPayIn = p.type === 'in';
    const title = isPayIn ? 'PAYMENT RECEIPT' : 'PAYMENT VOUCHER';
    let allocationsHtml = '';
    
    if (p.allocations && Object.keys(p.allocations).length > 0) {
        allocationsHtml = Object.entries(p.allocations).map(([inv, amt]) => 
            `<tr><td colspan="2" style="font-size:0.8rem;color:#555">Against Invoice: <b>${escapeHtml(inv)}</b></td><td style="text-align:right">₹ ${(+amt).toFixed(2)}</td></tr>`
        ).join('');
    } else if (p.invoiceNo && p.invoiceNo !== 'Advance') {
        allocationsHtml = `<tr><td colspan="2" style="font-size:0.8rem;color:#555">Against Invoice: <b>${escapeHtml(p.invoiceNo)}</b></td><td style="text-align:right">₹ ${(+p.amount).toFixed(2)}</td></tr>`;
    } else {
        allocationsHtml = `<tr><td colspan="2" style="font-size:0.8rem;color:#555">Advance / Unallocated</td><td style="text-align:right">₹ ${(+p.amount).toFixed(2)}</td></tr>`;
    }

    return `
<div class="page">
    <div class="voucher-title">${title}</div>
    <div class="inv-header">
        ${co.logo ? `<div class="inv-logo"><img src="${co.logo}" style="width:100%;max-height:60px;object-fit:contain"></div>` : ''}
        <div class="inv-co">
            <div class="co-name">${escapeHtml(co.name || 'Company Name')}</div>
            <div>${escapeHtml(co.address || '')}</div>
            ${co.city ? `<div>${escapeHtml(co.city)}</div>` : ''}
            <div>${co.phone ? 'Ph: ' + escapeHtml(co.phone) : ''} ${co.gstin ? ' | GSTIN: ' + escapeHtml(co.gstin) : ''}</div>
        </div>
    </div>
    
    <div class="meta-grid">
        <div class="meta-cell" style="border-right:1px solid #444; border-bottom:1px solid #444">
            <label>Receipt No.</label>
            <div style="font-weight:700;font-size:0.95rem">${escapeHtml(p.payNo || '-')}</div>
        </div>
        <div class="meta-cell" style="border-bottom:1px solid #444;text-align:right">
            <label>Date</label>
            <div style="font-weight:700;font-size:0.95rem">${fmtDate(p.date)}</div>
        </div>
        <div class="meta-cell" style="grid-column:span 2">
            <label>${isPayIn ? 'Received From:' : 'Paid To:'}</label>
            <div class="party-name">${escapeHtml(p.partyName)}</div>
        </div>
    </div>

    <table class="details-tbl">
        <thead>
            <tr>
                <th>Payment Mode</th>
                <th>Note / Reference</th>
                <th style="text-align:right;width:100px">Total Amount</th>
            </tr>
        </thead>
        <tbody>
            <tr>
                <td style="font-weight:600">${escapeHtml(p.mode || 'Cash')}</td>
                <td>${escapeHtml(p.note || '-')}</td>
                <td style="text-align:right;font-weight:800;font-size:1.1rem;white-space:nowrap">₹ ${(+p.amount).toFixed(2)}</td>
            </tr>
            ${allocationsHtml}
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" style="background:#f5f5f5;font-weight:700;font-size:0.85rem;padding:8px">
                    Amount in words: ${numberToWords(p.amount)} Rupees Only.
                </td>
            </tr>
        </tfoot>
    </table>

    <div class="sign-area">
        <div class="sign-box">Customer Signature</div>
        <div class="sign-box">Authorized Signatory</div>
    </div>
</div>`;
}

function printPaymentReceipt(id) {
    const p = DB.get('db_payments').find(x => x.id === id);
    if (!p) return;
    const co = DB.getObj('db_company') || {};
    const bodyHtml = _buildPaymentPageHtml(p, co);
    const title = `Payment Receipt - ${p.partyName}`;
    const css = _getPaymentPrintCss();

    let overlay = document.getElementById('inv-print-overlay');
    if (overlay) overlay.remove();
    overlay = document.createElement('div');
    overlay.id = 'inv-print-overlay';
    document.body.appendChild(overlay);
    overlay.innerHTML = `
        <style>
            #inv-print-overlay {
                position:fixed;inset:0;z-index:99999;background:#f1f3f5;
                display:flex;flex-direction:column;overflow:hidden;
            }
            #inv-print-topbar {
                display:flex;align-items:center;gap:10px;
                background:#1e293b;color:#fff;padding:10px 16px;
                font-size:0.95rem;font-weight:600;flex-shrink:0;
            }
            #inv-print-topbar button {
                background:none;border:none;color:#fff;font-size:1.3rem;
                cursor:pointer;padding:4px 8px;border-radius:6px;
            }
            #inv-print-doc-area {
                flex:1;overflow-y:auto;padding:16px;
                display:flex;justify-content:center;
            }
            #inv-print-doc-area .doc-wrap {
                background:#fff;box-shadow:0 4px 24px rgba(0,0,0,0.18);
                border-radius:4px;width:100%;max-width:600px;padding:16px;
            }
            #inv-print-action-bar {
                background:#fff;border-top:1px solid #e2e8f0;
                padding:12px 16px;display:flex;gap:10px;
                justify-content:center;flex-shrink:0;
                box-shadow:0 -2px 12px rgba(0,0,0,0.08);
            }
            #inv-print-action-bar button {
                flex:1;max-width:160px;padding:11px 8px;
                border-radius:10px;font-size:0.88rem;font-weight:600;
                border:none;cursor:pointer;display:flex;flex-direction:column;
                align-items:center;gap:4px;
            }
            #inv-print-action-bar button .ab-icon { font-size:1.4rem; }
            .ab-share { background:#6366f1;color:#fff; }
            .ab-download { background:#0ea5e9;color:#fff; }
            .ab-print { background:#f97316;color:#fff; }
            @media print {
                #inv-print-topbar, #inv-print-action-bar { display:none !important; }
                #inv-print-overlay { background:#fff;display:block !important;overflow:visible !important; }
                #inv-print-doc-area { overflow:visible;padding:0; }
                ${css}
            }
        </style>
        <style>${css}</style>
        <div id="inv-print-topbar">
            <button onclick="document.getElementById('inv-print-overlay').remove()">✕</button>
            <span style="flex:1">${escapeHtml(title)}</span>
        </div>
        <div id="inv-print-doc-area">
            <div class="doc-wrap">${bodyHtml}</div>
        </div>
        <div id="inv-print-action-bar">
            <button class="ab-share" onclick="_invPdfShare('${escapeHtml(title)}')">
                <span class="ab-icon material-symbols-outlined">share</span>Share
            </button>
            <button class="ab-download" onclick="window.print()">
                <span class="ab-icon material-symbols-outlined">save</span>Save PDF
            </button>
            <button class="ab-print" onclick="window.print()">
                <span class="ab-icon material-symbols-outlined">print</span>Print
            </button>
        </div>`;
    window.addEventListener('afterprint', () => {
        const el = document.getElementById('inv-print-overlay');
        if (el) el.remove();
    }, { once: true });
}


